    81→    }
    82→
    83→    /// Add iteration status (current iteration, budget, whether promise was found).
    84→    pub fn with_iteration_status(
    85→        mut self,
    86→        iteration: u32,
    87→        budget: u32,
    88→        promise_found: bool,
    89→    ) -> Self {
    90→        let status = if promise_found {
    91→            "COMPLETED".to_string()
    92→        } else {
    93→            format!("in progress ({}/{})", iteration, budget)
    94→        };
    95→        self.parts.push(format!("Iteration status: {}", status));
    96→        self
