100→/// Convert a title to a URL-safe slug, limited to `max_len` characters.
101→pub fn slugify(title: &str, max_len: usize) -> String {
102→    let slug: String = title
103→        .to_lowercase()
104→        .chars()
105→        .map(|c| if c.is_alphanumeric() { c } else { '-' })
106→        .collect::<String>()
107→        .split('-')
108→        .filter(|s| !s.is_empty())
109→        .collect::<Vec<_>>()
110→        .join("-");
111→    if slug.len() > max_len {
112→        slug[..slug.floor_char_boundary(max_len)]
113→            .trim_end_matches('-')
114→            .to_string()
115→    } else {
116→        slug
117→    }
118→}
119→
120→/// Create a git branch for the pipeline run. Returns the branch name.
121→async fn create_git_branch(project_path: &str, issue_id: i64, issue_title: &str) -> Result<String> {
122→    let slug = slugify(issue_title, 40);
123→    let branch_name = format!("forge/issue-{}-{}", issue_id, slug);
124→
125→    // Try creating a new branch
126→    let output = tokio::process::Command::new("git")
127→        .args(["checkout", "-b", &branch_name])
128→        .current_dir(project_path)
129→        .stdout(Stdio::null())
130→        .stderr(Stdio::piped())
131→        .output()
132→        .await
133→        .context("Failed to run git checkout -b")?;
134→
135→    if !output.status.success() {
136→        let stderr = String::from_utf8_lossy(&output.stderr);
137→
138→        // Branch already exists — switch to it instead
139→        if stderr.contains("already exists") {
140→            let switch = tokio::process::Command::new("git")
141→                .args(["checkout", &branch_name])
142→                .current_dir(project_path)
143→                .stdout(Stdio::null())
144→                .stderr(Stdio::piped())
145→                .output()
146→                .await
147→                .context("Failed to run git checkout")?;
148→
149→            if !switch.status.success() {
150→                let switch_stderr = String::from_utf8_lossy(&switch.stderr);
151→                anyhow::bail!(
152→                    "Failed to switch to existing branch {}: {}",
153→                    branch_name,
154→                    switch_stderr.trim()
155→                );
156→            }
157→        } else {
158→            anyhow::bail!("Failed to create branch {}: {}", branch_name, stderr.trim());
159→        }
160→    }
161→
162→    Ok(branch_name)
163→}
164→
165→/// Push branch and create a PR using `gh`. Returns the PR URL.
166→async fn create_pull_request(
167→    project_path: &str,
168→    branch_name: &str,
169→    issue_title: &str,
170→    issue_description: &str,
171→) -> Result<String> {
172→    // Push the branch
173→    let push_status = tokio::process::Command::new("git")
174→        .args(["push", "-u", "origin", branch_name])
175→        .current_dir(project_path)
176→        .stdout(Stdio::null())
177→        .stderr(Stdio::piped())
178→        .status()
179→        .await
180→        .context("Failed to push branch")?;
181→
182→    if !push_status.success() {
183→        anyhow::bail!("Failed to push branch {}", branch_name);
184→    }
185→
186→    // Create PR
187→    let body = format!(
188→        "## Summary\n\nAutomated implementation for: **{}**\n\n{}\n\n---\n*Created by Forge Factory*",
189→        issue_title,
190→        if issue_description.is_empty() {
191→            "No description provided."
192→        } else {
193→            issue_description
194→        }
195→    );
196→
197→    let output = tokio::process::Command::new("gh")
198→        .args(["pr", "create", "--title", issue_title, "--body", &body])
199→        .current_dir(project_path)
200→        .stdout(Stdio::piped())
201→        .stderr(Stdio::piped())
202→        .output()
203→        .await
204→        .context("Failed to run gh pr create")?;
205→
206→    if !output.status.success() {
207→        let stderr = String::from_utf8_lossy(&output.stderr);
208→        anyhow::bail!("Failed to create PR: {}", stderr);
209→    }
210→
211→    let pr_url = String::from_utf8(output.stdout)
212→        .context("Invalid UTF-8 in gh output")?
213→        .trim()
214→        .to_string();
215→
216→    Ok(pr_url)
217→}
