219→/// Tracks progress parsed from subprocess stdout lines.
220→#[derive(Debug, Clone, Default, serde::Deserialize)]
221→struct ProgressInfo {
222→    #[serde(default)]
223→    phase: Option<i32>,
224→    #[serde(default)]
225→    phase_count: Option<i32>,
226→    #[serde(default)]
227→    iteration: Option<i32>,
228→}
