230→/// Handle to a running pipeline — either a local subprocess or a Docker container.
231→pub enum RunHandle {
232→    Process(tokio::process::Child),
233→    Container(String), // container ID
234→}
235→
236→/// Manages pipeline execution for factory issues.
237→/// Tracks running child processes so they can be cancelled.
238→pub struct PipelineRunner {
239→    #[allow(dead_code)] // Used by tests; start_run now requires DB project lookup
240→    project_path: String,
241→    /// Map from run_id to the run handle for running pipelines.
242→    running_processes: Arc<tokio::sync::Mutex<HashMap<i64, RunHandle>>>,
243→    /// Docker sandbox, if available and enabled.
244→    sandbox: Option<Arc<DockerSandbox>>,
245→    /// Per-project git lock map for serializing git-mutating operations.
246→    git_locks: GitLockMap,
247→}
248→
249→impl PipelineRunner {
250→    pub fn new(project_path: &str, sandbox: Option<Arc<DockerSandbox>>) -> Self {
251→        Self {
252→            project_path: project_path.to_string(),
253→            running_processes: Arc::new(tokio::sync::Mutex::new(HashMap::new())),
254→            sandbox,
255→            git_locks: GitLockMap::default(),
256→        }
257→    }
258→
259→    /// Cancel a running pipeline by killing its child process and updating the DB.
260→    /// Returns the updated PipelineRun or an error if the run doesn't exist or DB update fails.
261→    pub async fn cancel(
262→        &self,
263→        run_id: i64,
264→        db: &DbHandle,
265→        tx: &broadcast::Sender<String>,
266→    ) -> Result<PipelineRun> {
267→        // Kill the child process or stop the container if it exists
268→        {
269→            let mut processes = self.running_processes.lock().await;
270→            if let Some(handle) = processes.remove(&run_id) {
271→                match handle {
272→                    RunHandle::Process(mut child) => {
273→                        if let Err(e) = child.kill().await {
274→                            eprintln!(
275→                                "[factory] WARNING: failed to kill process for run {}: {}",
276→                                run_id, e
277→                            );
278→                        }
279→                    }
280→                    RunHandle::Container(container_id) => {
281→                        if let Some(ref sandbox) = self.sandbox
282→                            && let Err(e) = sandbox.stop(&container_id).await
283→                        {
284→                            eprintln!(
285→                                "[factory] WARNING: failed to stop container {} for run {}: {}",
286→                                container_id, run_id, e
287→                            );
288→                        }
289→                    }
290→                }
291→            }
292→        }
293→
294→        // Update DB status to Cancelled and move issue back to Ready
295→        let run = db.cancel_pipeline_run(run_id).await?;
