 333→    /// Stop all active pipeline containers/processes on shutdown.
 334→    pub async fn shutdown(&self) {
 335→        let mut processes = self.running_processes.lock().await;
 336→        for (run_id, handle) in processes.drain() {
 337→            eprintln!("[factory] Shutting down pipeline run {}", run_id);
 338→            match handle {
 339→                RunHandle::Process(mut child) => {
 340→                    if let Err(e) = child.kill().await {
 341→                        eprintln!(
