 361→    /// Execute a pipeline run using the agent team approach:
 362→    /// 1. Call planner to decompose the issue into tasks
 363→    /// 2. Create team + tasks in DB
 364→    /// 3. Broadcast TeamCreated to connected WebSocket clients
 365→    /// 4. Execute tasks wave by wave (with worktree isolation and merging between waves)
 366→    /// 5. After each wave, merge completed task branches back into the base branch
 367→    ///    (modifies project directory git state -- requires exclusive access)
 368→    ///
 369→    /// Returns `Ok(PlanOutcome::FallbackToForge)` when the caller should use the sequential
 370→    /// forge pipeline instead. This happens in two cases:
 371→    /// - The planner returns a single-task sequential plan (issue is too simple for parallelism)
 372→    /// - Planning fails entirely (LLM error, parse failure, validation failure) and the
 373→    ///   generated fallback plan is a single sequential task
 374→    #[allow(clippy::too_many_arguments)]
 375→    async fn execute_agent_team(
 376→        project_path: &str,
 377→        run_id: i64,
 378→        issue_title: &str,
 379→        issue_description: &str,
 380→        issue_labels: &[String],
 381→        branch_name: &Option<String>,
 382→        db: &DbHandle,
 383→        tx: &broadcast::Sender<String>,
 384→        git_locks: &GitLockMap,
 385→        planner: &dyn PlanProvider,
 386→        task_runner: &Arc<dyn TaskRunner>,
 387→    ) -> Result<PlanOutcome> {
 388→        // Step 1: Plan
 389→        let plan = match planner
 390→            .plan(issue_title, issue_description, issue_labels)
 391→            .await
 392→        {
 393→            Ok(plan) => plan,
 394→            Err(e) => {
 395→                eprintln!(
 396→                    "[pipeline] run_id={}: Planning failed, falling back to single task: {:#}",
 397→                    run_id, e
 398→                );
 399→                // Broadcast a warning to the UI
 400→                broadcast_message(
 401→                    tx,
 402→                    &WsMessage::AgentSignal {
 403→                        run_id,
 404→                        task_id: 0,
 405→                        signal_type: SignalType::Blocker,
 406→                        content: format!("Planning failed, using single-task fallback: {}", e),
 407→                    },
 408→                );
 409→                super::planner::PlanResponse::fallback(issue_title, issue_description)
 410→            }
 411→        };
 412→
 413→        // If it's a single sequential task, signal fallback
 414→        let is_sequential = plan
 415→            .strategy
 416→            .parse::<super::models::ExecutionStrategy>()
 417→            .map(|s| s == super::models::ExecutionStrategy::Sequential)
 418→            .unwrap_or(false);
 419→        if plan.tasks.len() <= 1 && is_sequential {
 420→            return Ok(PlanOutcome::FallbackToForge);
 421→        }
 422→
 423→        // Step 2: Create team + tasks in DB
 424→        // Parse strategy/isolation/roles outside the closure (they use &str references from plan)
 425→        let strategy: ExecutionStrategy = plan
 426→            .strategy
 427→            .parse()
 428→            .map_err(|_| anyhow::anyhow!("Invalid strategy from planner: '{}'", plan.strategy))?;
 429→        let isolation: IsolationStrategy = plan
 430→            .isolation
 431→            .parse()
 432→            .map_err(|_| anyhow::anyhow!("Invalid isolation from planner: '{}'", plan.isolation))?;
 433→        let mut parsed_tasks: Vec<(String, String, AgentRole, i32, Vec<i32>, IsolationStrategy)> =
 434→            Vec::new();
 435→        for plan_task in &plan.tasks {
 436→            let role: AgentRole = plan_task
 437→                .role
 438→                .parse()
 439→                .map_err(|_| anyhow::anyhow!("Invalid role from planner: '{}'", plan_task.role))?;
 440→            let task_isolation: IsolationStrategy = plan_task.isolation.parse().map_err(|_| {
 441→                anyhow::anyhow!("Invalid isolation from planner: '{}'", plan_task.isolation)
 442→            })?;
 443→            parsed_tasks.push((
 444→                plan_task.name.clone(),
 445→                plan_task.description.clone(),
 446→                role,
 447→                plan_task.wave,
 448→                plan_task.depends_on.clone(),
 449→                task_isolation,
 450→            ));
 451→        }
 452→        let reasoning = plan.reasoning.clone();
 453→        let team = db.create_agent_team(run_id, &strategy, &isolation, &reasoning).await?;
 454→
 455→        let mut db_tasks = Vec::new();
 456→        for (name, description, role, wave, depends_on, task_isolation) in &parsed_tasks {
 457→            let depends: Vec<i64> = depends_on
 458→                .iter()
 459→                .filter_map(|&idx| db_tasks.get(idx as usize).map(|t: &AgentTask| t.id))
 460→                .collect();
 461→            let task = db.create_agent_task(
 462→                team.id,
 463→                name,
 464→                description,
 465→                role,
 466→                *wave,
 467→                &depends,
 468→                task_isolation,
 469→            ).await?;
 470→            db_tasks.push(task);
 471→        }
 472→
 473→        // Step 3: Broadcast TeamCreated
 474→        broadcast_message(
 475→            tx,
 476→            &WsMessage::TeamCreated {
 477→                run_id,
 478→                team_id: team.id,
 479→                strategy: team.strategy.clone(),
 480→                isolation: team.isolation.clone(),
 481→                plan_summary: plan.reasoning.clone(),
 482→                tasks: db_tasks.clone(),
 483→            },
 484→        );
 485→
 486→        // Step 4: Execute wave by wave
 487→        let executor = Arc::clone(task_runner);
 488→        let max_wave = plan.max_wave();
 489→        let base_branch = branch_name.as_deref().unwrap_or("main");
 490→
 491→        for wave in 0..=max_wave {
 492→            let wave_tasks: Vec<&AgentTask> = db_tasks.iter().filter(|t| t.wave == wave).collect();
 493→
 494→            if wave_tasks.is_empty() {
 495→                continue;
 496→            }
 497→
 498→            let task_ids: Vec<i64> = wave_tasks.iter().map(|t| t.id).collect();
 499→            broadcast_message(
 500→                tx,
 501→                &WsMessage::WaveStarted {
 502→                    run_id,
 503→                    team_id: team.id,
 504→                    wave,
 505→                    task_ids: task_ids.clone(),
 506→                },
 507→            );
 508→
 509→            // Set up worktrees for tasks that need isolation
 510→            let mut task_working_dirs: Vec<(AgentTask, std::path::PathBuf, Option<String>)> =
 511→                Vec::new();
 512→            for task in &wave_tasks {
 513→                let (working_dir, task_branch) = if task.isolation_type
 514→                    == IsolationStrategy::Worktree
 515→                {
 516→                    match executor.setup_worktree(run_id, task, base_branch).await {
 517→                        Ok((path, branch)) => (path, Some(branch)),
 518→                        Err(e) => {
 519→                            if wave_tasks.len() > 1 {
 520→                                // Multiple parallel tasks need isolation; falling back to shared
 521→                                // directory would cause conflicts.
 522→                                anyhow::bail!(
 523→                                    "Worktree setup failed for task {} ({}) in parallel wave \
 524→                                     (wave has {} tasks, shared directory fallback is unsafe): {:#}",
 525→                                    task.id,
 526→                                    task.name,
 527→                                    wave_tasks.len(),
 528→                                    e
 529→                                );
 530→                            }
 531→                            eprintln!(
 532→                                "[pipeline] run_id={}: worktree setup failed for task {} ({}): {:#}. \
 533→                                 Falling back to shared directory (single-task wave).",
 534→                                run_id, task.id, task.name, e
 535→                            );
 536→                            broadcast_message(
 537→                                tx,
 538→                                &WsMessage::AgentSignal {
 539→                                    run_id,
 540→                                    task_id: task.id,
 541→                                    signal_type: SignalType::Blocker,
 542→                                    content: format!(
 543→                                        "Worktree isolation failed, running in shared directory: {}",
 544→                                        e
 545→                                    ),
 546→                                },
 547→                            );
 548→                            (std::path::PathBuf::from(project_path), None)
 549→                        }
 550→                    }
 551→                } else {
 552→                    (std::path::PathBuf::from(project_path), None)
 553→                };
 554→                task_working_dirs.push(((*task).clone(), working_dir, task_branch));
 555→            }
 556→
 557→            // Run tasks in parallel
 558→            let mut handles = Vec::new();
 559→            for (task, working_dir, _branch) in &task_working_dirs {
 560→                let executor_ref = Arc::clone(task_runner);
 561→                let task_clone = task.clone();
 562→                let dir_clone = working_dir.clone();
 563→                let run_id_clone = run_id;
 564→                let use_team = wave_tasks.len() > 1;
 565→                let worktree_path = if task.isolation_type == IsolationStrategy::Worktree {
 566→                    Some(working_dir.clone())
 567→                } else {
 568→                    None
 569→                };
 570→
 571→                let handle = tokio::spawn(async move {
 572→                    executor_ref
 573→                        .run_task(
 574→                            run_id_clone,
 575→                            &task_clone,
 576→                            use_team,
 577→                            &dir_clone,
 578→                            worktree_path,
 579→                        )
 580→                        .await
 581→                });
 582→                handles.push(handle);
 583→            }
 584→
 585→            // Wait for all tasks in this wave
 586→            let mut success_count: u32 = 0;
 587→            let mut failed_count: u32 = 0;
 588→            for handle in handles {
 589→                match handle.await {
 590→                    Ok(Ok(true)) => success_count += 1,
 591→                    Ok(Ok(false)) => {
 592→                        // Task completed but reported failure (DB already updated by run_task)
 593→                        failed_count += 1;
 594→                    }
 595→                    Ok(Err(e)) => {
 596→                        eprintln!(
 597→                            "[pipeline] run_id={}: task execution error: {:#}",
 598→                            run_id, e
 599→                        );
 600→                        failed_count += 1;
 601→                    }
 602→                    Err(join_err) => {
 603→                        eprintln!("[pipeline] run_id={}: task panicked: {}", run_id, join_err);
 604→                        failed_count += 1;
 605→                    }
 606→                }
 607→            }
 608→
 609→            // Collect worktree paths for cleanup (before merge loop, so we clean all even on conflict)
 610→            let worktree_paths: Vec<_> = task_working_dirs
 611→                .iter()
 612→                .filter(|(task, _, _)| task.isolation_type == IsolationStrategy::Worktree)
 613→                .map(|(_, dir, _)| dir.clone())
 614→                .collect();
 615→
 616→            // Merge branches from worktrees (under project lock)
 617→            if wave_tasks.len() > 1 || task_working_dirs.iter().any(|(_, _, b)| b.is_some()) {
 618→                let git_lock = git_locks.get(project_path).await;
 619→                let _guard = git_lock.lock().await;
 620→
 621→                broadcast_message(tx, &WsMessage::MergeStarted { run_id, wave });
 622→
 623→                let mut merge_conflicts = false;
 624→                for (_task, _working_dir, task_branch) in &task_working_dirs {
 625→                    if let Some(branch) = task_branch {
 626→                        let merged = executor.merge_branch(branch, base_branch).await;
 627→                        match merged {
 628→                            Ok(true) => { /* success */ }
 629→                            Ok(false) => {
 630→                                eprintln!(
 631→                                    "[pipeline] run_id={}: merge conflict for branch {}",
 632→                                    run_id, branch
 633→                                );
 634→                                merge_conflicts = true;
 635→                                break;
 636→                            }
 637→                            Err(e) => {
 638→                                eprintln!(
 639→                                    "[pipeline] run_id={}: merge command failed for branch {}: {:#}",
 640→                                    run_id, branch, e
 641→                                );
 642→                                merge_conflicts = true;
 643→                                break;
 644→                            }
 645→                        }
 646→                    }
 647→                }
 648→
 649→                broadcast_message(
 650→                    tx,
 651→                    &WsMessage::MergeCompleted {
 652→                        run_id,
 653→                        wave,
 654→                        conflicts: merge_conflicts,
 655→                    },
 656→                );
 657→                // git lock released at end of block
 658→            }
 659→
 660→            // Always clean up ALL worktrees, even after merge conflict
 661→            for dir in &worktree_paths {
 662→                if let Err(e) = executor.cleanup_worktree(dir).await {
 663→                    eprintln!(
 664→                        "[pipeline] Failed to clean up worktree {}: {:#}",
 665→                        dir.display(),
 666→                        e
 667→                    );
 668→                }
 669→            }
 670→
 671→            broadcast_message(
 672→                tx,
 673→                &WsMessage::WaveCompleted {
 674→                    run_id,
 675→                    team_id: team.id,
 676→                    wave,
 677→                    success_count,
 678→                    failed_count,
