1129→/// Auto-generate spec and phases from an issue description.
1130→/// Writes a design doc to `.forge/spec.md`, then runs `forge generate`.
1131→/// Returns Ok(true) if phases were generated successfully, Ok(false) if generation
1132→/// failed or produced no output (caller should fall back to direct invocation).
1133→async fn auto_generate_phases(
1134→    project_path: &str,
1135→    issue_title: &str,
1136→    issue_description: &str,
1137→) -> Result<bool> {
1138→    // Ensure .forge directory exists
1139→    let forge_dir = std::path::Path::new(project_path).join(".forge");
1140→    if !forge_dir.exists() {
1141→        tokio::fs::create_dir_all(&forge_dir)
1142→            .await
1143→            .context("Failed to create .forge directory")?;
1144→    }
1145→
1146→    // Write a design document from the issue
1147→    let design_content = format!(
1148→        "# {}\n\n## Overview\n\n{}\n\n## Requirements\n\n- Implement the feature described above\n- Ensure all existing tests continue to pass\n- Add tests for new functionality\n",
1149→        issue_title,
1150→        if issue_description.is_empty() {
1151→            "No additional details provided."
1152→        } else {
1153→            issue_description
1154→        }
1155→    );
1156→    let design_path = forge_dir.join("spec.md");
1157→    tokio::fs::write(&design_path, &design_content)
1158→        .await
1159→        .context("Failed to write design document")?;
1160→
1161→    // Run forge generate to create phases.json
1162→    let forge_cmd = std::env::var("FORGE_CMD").unwrap_or_else(|_| "forge".to_string());
1163→    let status = match tokio::process::Command::new(&forge_cmd)
1164→        .arg("generate")
1165→        .current_dir(project_path)
1166→        .stdout(Stdio::piped())
1167→        .stderr(Stdio::piped())
1168→        .status()
1169→        .await
1170→    {
1171→        Ok(s) => s,
1172→        Err(e) => {
1173→            eprintln!("[pipeline] Failed to spawn '{}': {e}", forge_cmd);
1174→            return Ok(false);
1175→        }
1176→    };
1177→
1178→    if status.success() && has_forge_phases(project_path) {
1179→        Ok(true)
1180→    } else {
1181→        // Generation failed — fall back to simple Claude invocation
1182→        Ok(false)
1183→    }
1184→}
