1210→            "Implement the following issue:\n\nTitle: {}\n\nDescription: {}\n",
1211→            issue_title, issue_description
1212→        );
1213→        let mut cmd = tokio::process::Command::new(&claude_cmd);
1214→        cmd.arg("--print")
1215→            .arg("--verbose")
1216→            .arg("--output-format")
1217→            .arg("stream-json")
1218→            .arg("--dangerously-skip-permissions")
1219→            .arg(&prompt)
1220→            .env_remove("CLAUDECODE")
1221→            .current_dir(project_path)
1222→            .stdout(Stdio::piped())
1223→            .stderr(Stdio::piped());
1224→        cmd
1225→    }
1226→}
