1228→#[derive(Debug, Clone, PartialEq, Serialize)]
1229→#[serde(tag = "content_type")]
1230→#[allow(dead_code)]
1231→pub enum StreamJsonEvent {
1232→    Text {
1233→        text: String,
1234→    },
1235→    ToolStart {
1236→        tool_name: String,
1237→        tool_id: String,
1238→        input_summary: String,
1239→    },
1240→    ToolEnd {
1241→        tool_id: String,
1242→        output_preview: String,
1243→    },
1244→    Thinking {
1245→        text: String,
1246→    },
1247→    Skip,
1248→}
1249→
1250→pub fn parse_stream_json_line(line: &str) -> StreamJsonEvent {
1251→    // Try to parse as JSON
1252→    let json: serde_json::Value = match serde_json::from_str(line) {
1253→        Ok(v) => v,
1254→        Err(_) => {
1255→            // Not JSON — treat as plain text
1256→            return StreamJsonEvent::Text {
1257→                text: line.to_string(),
1258→            };
1259→        }
1260→    };
1261→
1262→    // Skip metadata-only messages
1263→    let msg_type = json.get("type").and_then(|t| t.as_str()).unwrap_or("");
1264→    match msg_type {
1265→        "message_start" | "message_stop" | "message_delta" | "content_block_stop" | "result" => {
1266→            return StreamJsonEvent::Skip;
1267→        }
1268→        _ => {}
1269→    }
1270→
1271→    // content_block_delta with text_delta → Text
1272→    if msg_type == "content_block_delta"
1273→        && let Some(delta) = json.get("delta")
1274→    {
1275→        if delta.get("type").and_then(|t| t.as_str()) == Some("text_delta")
1276→            && let Some(text) = delta.get("text").and_then(|t| t.as_str())
1277→        {
1278→            return StreamJsonEvent::Text {
1279→                text: text.to_string(),
1280→            };
1281→        }
1282→        if delta.get("type").and_then(|t| t.as_str()) == Some("thinking_delta")
1283→            && let Some(text) = delta.get("thinking").and_then(|t| t.as_str())
1284→        {
1285→            return StreamJsonEvent::Thinking {
1286→                text: text.to_string(),
1287→            };
1288→        }
1289→    }
1290→
1291→    // content_block_start with tool_use → ToolStart
1292→    if msg_type == "content_block_start"
1293→        && let Some(cb) = json.get("content_block")
1294→        && cb.get("type").and_then(|t| t.as_str()) == Some("tool_use")
1295→    {
1296→        let tool_name = cb
1297→            .get("name")
1298→            .and_then(|n| n.as_str())
1299→            .unwrap_or("unknown")
1300→            .to_string();
1301→        let tool_id = cb
1302→            .get("id")
1303→            .and_then(|i| i.as_str())
1304→            .unwrap_or("")
1305→            .to_string();
1306→        let input_summary = extract_tool_input_summary(&tool_name, cb.get("input"));
1307→        return StreamJsonEvent::ToolStart {
1308→            tool_name,
1309→            tool_id,
1310→            input_summary,
1311→        };
1312→    }
1313→
1314→    // Legacy format: subtype == "tool_use"
1315→    if json.get("subtype").and_then(|s| s.as_str()) == Some("tool_use") {
1316→        let tool_name = json
1317→            .get("tool_name")
1318→            .and_then(|n| n.as_str())
1319→            .unwrap_or("unknown")
1320→            .to_string();
1321→        let tool_id = json
1322→            .get("tool_use_id")
1323→            .and_then(|i| i.as_str())
1324→            .unwrap_or("")
1325→            .to_string();
1326→        let input_summary = extract_tool_input_summary(&tool_name, json.get("input"));
1327→        return StreamJsonEvent::ToolStart {
1328→            tool_name,
1329→            tool_id,
1330→            input_summary,
1331→        };
1332→    }
1333→
1334→    // Full assistant message with content array containing tool_use
1335→    if json.get("role").and_then(|r| r.as_str()) == Some("assistant")
1336→        && let Some(content) = json.get("content").and_then(|c| c.as_array())
1337→    {
1338→        for block in content {
1339→            if block.get("type").and_then(|t| t.as_str()) == Some("tool_use") {
1340→                let tool_name = block
1341→                    .get("name")
1342→                    .and_then(|n| n.as_str())
1343→                    .unwrap_or("unknown")
1344→                    .to_string();
1345→                let tool_id = block
1346→                    .get("id")
1347→                    .and_then(|i| i.as_str())
1348→                    .unwrap_or("")
1349→                    .to_string();
1350→                let input_summary = extract_tool_input_summary(&tool_name, block.get("input"));
1351→                return StreamJsonEvent::ToolStart {
1352→                    tool_name,
1353→                    tool_id,
1354→                    input_summary,
1355→                };
1356→            }
1357→        }
1358→    }
1359→
1360→    StreamJsonEvent::Skip
1361→}
1362→
1363→pub fn extract_tool_input_summary(tool_name: &str, input: Option<&serde_json::Value>) -> String {
1364→    let input = match input {
1365→        Some(v) => v,
1366→        None => return String::new(),
1367→    };
1368→
1369→    match tool_name {
1370→        "Read" | "read" | "file_read" => input
1371→            .get("file_path")
1372→            .and_then(|p| p.as_str())
1373→            .unwrap_or("")
1374→            .to_string(),
1375→        "Write" | "write" | "file_write" => input
1376→            .get("file_path")
1377→            .and_then(|p| p.as_str())
1378→            .unwrap_or("")
1379→            .to_string(),
1380→        "Edit" | "edit" | "file_edit" => input
1381→            .get("file_path")
1382→            .and_then(|p| p.as_str())
1383→            .unwrap_or("")
1384→            .to_string(),
1385→        "Bash" | "bash" | "execute_command" => {
1386→            let cmd = input.get("command").and_then(|c| c.as_str()).unwrap_or("");
1387→            if cmd.len() > 80 {
1388→                format!("{}...", &cmd[..80])
1389→            } else {
1390→                cmd.to_string()
1391→            }
1392→        }
1393→        _ => String::new(),
1394→    }
1395→}
1396→
1397→pub fn extract_file_change(
1398→    tool_name: &str,
1399→    input: Option<&serde_json::Value>,
1400→) -> Option<(String, FileAction)> {
1401→    let input = input?;
1402→
1403→    match tool_name {
1404→        "Write" | "write" | "file_write" => {
1405→            let path = input.get("file_path").and_then(|p| p.as_str())?;
1406→            Some((path.to_string(), FileAction::Created))
1407→        }
1408→        "Edit" | "edit" | "file_edit" => {
1409→            let path = input.get("file_path").and_then(|p| p.as_str())?;
1410→            Some((path.to_string(), FileAction::Modified))
1411→        }
1412→        _ => None,
1413→    }
1414→}
