1416→/// Execute a forge pipeline for the given issue, streaming stdout line by line.
1417→/// Uses `forge swarm` if phases.json exists, otherwise falls back to `claude --print`.
1418→/// Monitors output for progress JSON and emits PipelineProgress WS events.
1419→async fn execute_pipeline_streaming(
1420→    run_id: i64,
1421→    project_path: &str,
1422→    issue_title: &str,
1423→    issue_description: &str,
1424→    running_processes: &Arc<tokio::sync::Mutex<HashMap<i64, RunHandle>>>,
1425→    db: &DbHandle,
1426→    tx: &broadcast::Sender<String>,
1427→) -> Result<String> {
1428→    let mut cmd = build_execution_command(project_path, issue_title, issue_description);
1429→    let mut child = cmd.spawn().context("Failed to spawn pipeline process")?;
1430→
1431→    // Take stdout before storing child — we need ownership of the stdout handle
1432→    let stdout = child
1433→        .stdout
1434→        .take()
1435→        .context("Failed to capture stdout from child process")?;
1436→
1437→    // Store the child handle for cancellation
1438→    {
1439→        let mut processes = running_processes.lock().await;
1440→        processes.insert(run_id, RunHandle::Process(child));
1441→    }
1442→
1443→    // Read stdout line by line, looking for progress updates
1444→    let reader = BufReader::new(stdout);
1445→    let mut lines = reader.lines();
1446→    let mut all_output = String::new();
1447→    let mut last_output_broadcast = std::time::Instant::now() - std::time::Duration::from_secs(1);
1448→
1449→    while let Some(line) = lines
1450→        .next_line()
1451→        .await
1452→        .context("Failed to read stdout line")?
1453→    {
1454→        all_output.push_str(&line);
1455→        all_output.push('\n');
1456→
1457→        // Try to parse as DAG executor PhaseEvent first (from forge swarm)
1458→        if let Some(event) = try_parse_phase_event(&line) {
1459→            process_phase_event(&event, run_id, db, tx).await;
1460→            continue;
1461→        }
1462→
1463→        // Fall back to simple progress JSON (from claude --print)
1464→        if let Some(progress) = try_parse_progress(&line) {
1465→            // Update DB with progress
1466→            if let Err(e) = db
1467→                .update_pipeline_progress(run_id, progress.phase_count, progress.phase, progress.iteration)
1468→                .await
1469→            {
1470→                broadcast_message(
1471→                    tx,
1472→                    &WsMessage::PipelineError {
1473→                        run_id,
1474→                        message: format!("Failed to update pipeline progress: {:#}", e),
1475→                    },
1476→                );
1477→            }
1478→
1479→            // Compute a rough percentage
1480→            let percent = compute_percent(&progress);
1481→
1482→            // Broadcast progress event
1483→            broadcast_message(
1484→                tx,
1485→                &WsMessage::PipelineProgress {
1486→                    run_id,
1487→                    phase: progress.phase.unwrap_or(0),
1488→                    iteration: progress.iteration.unwrap_or(0),
1489→                    percent,
1490→                },
1491→            );
1492→        } else if !line.is_empty() {
1493→            let event = parse_stream_json_line(&line);
1494→            match event {
1495→                StreamJsonEvent::Skip => {}
1496→                StreamJsonEvent::Text { ref text } | StreamJsonEvent::Thinking { ref text } => {
1497→                    // Throttle text/thinking events to 200ms
1498→                    if last_output_broadcast.elapsed() >= std::time::Duration::from_millis(200)
1499→                        && !text.is_empty()
1500→                    {
1501→                        let content_type = match &event {
1502→                            StreamJsonEvent::Thinking { .. } => "thinking",
1503→                            _ => "text",
1504→                        };
1505→                        broadcast_message(
1506→                            tx,
1507→                            &WsMessage::PipelineOutputEvent {
1508→                                run_id,
1509→                                content_type: content_type.to_string(),
1510→                                content: text.clone(),
1511→                                tool_id: None,
1512→                                input_summary: None,
1513→                            },
1514→                        );
1515→                        // Also send legacy PipelineOutput for backward compat
1516→                        broadcast_message(
1517→                            tx,
1518→                            &WsMessage::PipelineOutput {
1519→                                run_id,
1520→                                content: text.clone(),
1521→                            },
1522→                        );
1523→                        last_output_broadcast = std::time::Instant::now();
1524→                    }
1525→                }
1526→                StreamJsonEvent::ToolStart {
1527→                    ref tool_name,
1528→                    ref tool_id,
1529→                    ref input_summary,
1530→                } => {
1531→                    broadcast_message(
1532→                        tx,
1533→                        &WsMessage::PipelineOutputEvent {
1534→                            run_id,
1535→                            content_type: "tool_start".to_string(),
1536→                            content: tool_name.clone(),
1537→                            tool_id: Some(tool_id.clone()),
1538→                            input_summary: Some(input_summary.clone()),
1539→                        },
1540→                    );
1541→                    // Also send legacy PipelineOutput
1542→                    broadcast_message(
1543→                        tx,
1544→                        &WsMessage::PipelineOutput {
1545→                            run_id,
1546→                            content: format!("[{}] {}", tool_name, input_summary),
1547→                        },
1548→                    );
1549→                    // Check for file changes
1550→                    let input_json: Option<serde_json::Value> =
1551→                        serde_json::from_str::<serde_json::Value>(&line)
1552→                            .ok()
1553→                            .and_then(|v| {
1554→                                // Try content_block_start format
1555→                                if let Some(cb) = v.get("content_block") {
1556→                                    return cb.get("input").cloned();
1557→                                }
1558→                                // Try legacy format
1559→                                v.get("input").cloned()
1560→                            });
1561→                    if let Some(ref input_val) = input_json
1562→                        && let Some((file_path, action)) =
1563→                            extract_file_change(tool_name, Some(input_val))
1564→                    {
1565→                        broadcast_message(
1566→                            tx,
1567→                            &WsMessage::PipelineFileChanged {
1568→                                run_id,
1569→                                file_path,
1570→                                action,
1571→                            },
1572→                        );
1573→                    }
1574→                    last_output_broadcast = std::time::Instant::now();
1575→                }
1576→                StreamJsonEvent::ToolEnd {
1577→                    ref tool_id,
1578→                    ref output_preview,
1579→                } => {
1580→                    broadcast_message(
1581→                        tx,
1582→                        &WsMessage::PipelineOutputEvent {
1583→                            run_id,
1584→                            content_type: "tool_end".to_string(),
1585→                            content: output_preview.clone(),
1586→                            tool_id: Some(tool_id.clone()),
1587→                            input_summary: None,
1588→                        },
1589→                    );
1590→                }
1591→            }
1592→        }
1593→    }
1594→
1595→    // Wait for the process to finish — retrieve the child from the map
1596→    let status = {
1597→        let mut processes = running_processes.lock().await;
1598→        if let Some(handle) = processes.remove(&run_id) {
1599→            match handle {
1600→                RunHandle::Process(mut child) => child
1601→                    .wait()
1602→                    .await
1603→                    .context("Failed to wait for child process")?,
1604→                RunHandle::Container(_) => {
1605→                    anyhow::bail!("Unexpected container handle in local execution path")
1606→                }
1607→            }
1608→        } else {
1609→            // Process was already removed (e.g., cancelled)
1610→            anyhow::bail!("Pipeline was cancelled")
1611→        }
1612→    };
1613→
1614→    if status.success() {
1615→        // Take last 500 chars as summary
1616→        let summary = if all_output.len() > 500 {
1617→            format!("...{}", &all_output[all_output.len() - 500..])
1618→        } else {
1619→            all_output
1620→        };
1621→        Ok(summary)
1622→    } else {
1623→        anyhow::bail!(
1624→            "Pipeline process failed with exit code: {:?}",
1625→            status.code()
1626→        )
1627→    }
1628→}
