1630→/// Execute a pipeline in a Docker container, streaming logs line by line.
1631→#[allow(clippy::too_many_arguments)]
1632→async fn execute_pipeline_docker(
1633→    run_id: i64,
1634→    project_path: &str,
1635→    issue_title: &str,
1636→    issue_description: &str,
1637→    sandbox: &Arc<DockerSandbox>,
1638→    running_processes: &Arc<tokio::sync::Mutex<HashMap<i64, RunHandle>>>,
1639→    db: &DbHandle,
1640→    tx: &broadcast::Sender<String>,
1641→    timeout_secs: u64,
1642→) -> Result<String> {
1643→    let config = match SandboxConfig::load(std::path::Path::new(project_path)) {
1644→        Ok(c) => c,
1645→        Err(e) => {
1646→            eprintln!("[pipeline] Failed to load sandbox config, using defaults: {e}");
1647→            SandboxConfig::default()
1648→        }
1649→    };
1650→
1651→    // Build the command — same logic as local
1652→    let command = if has_forge_phases(project_path) {
1653→        let forge_cmd = std::env::var("FORGE_CMD").unwrap_or_else(|_| "forge".to_string());
1654→        vec![
1655→            forge_cmd,
1656→            "swarm".into(),
1657→            "--max-parallel".into(),
1658→            "4".into(),
1659→            "--fail-fast".into(),
1660→        ]
1661→    } else {
1662→        let claude_cmd = std::env::var("CLAUDE_CMD").unwrap_or_else(|_| "claude".into());
1663→        let prompt = format!(
1664→            "Implement the following issue:\n\nTitle: {}\n\nDescription: {}\n",
1665→            issue_title, issue_description
1666→        );
1667→        vec![
1668→            claude_cmd,
1669→            "--print".into(),
1670→            "--dangerously-skip-permissions".into(),
1671→            prompt,
1672→        ]
1673→    };
1674→
1675→    // Build environment variables to inject
1676→    let mut env = Vec::new();
1677→    if let Ok(key) = std::env::var("ANTHROPIC_API_KEY") {
1678→        env.push(format!("ANTHROPIC_API_KEY={}", key));
1679→    }
1680→    if let Ok(token) = std::env::var("GITHUB_TOKEN") {
1681→        env.push(format!("GITHUB_TOKEN={}", token));
1682→    }
1683→    if let Ok(token) = std::env::var("CLAUDE_CODE_OAUTH_TOKEN") {
1684→        env.push(format!("CLAUDE_CODE_OAUTH_TOKEN={}", token));
1685→    }
1686→
1687→    // Get project name for volume naming
1688→    let project_name = std::path::Path::new(project_path)
1689→        .file_name()
1690→        .and_then(|n| n.to_str())
1691→        .unwrap_or("unknown");
1692→
1693→    let (container_id, mut line_rx) = sandbox
1694→        .run_pipeline(
1695→            std::path::Path::new(project_path),
1696→            command,
1697→            &config,
1698→            env,
1699→            run_id,
1700→            project_name,
1701→        )
1702→        .await?;
1703→
1704→    // Store the container handle for cancellation
1705→    {
1706→        let mut processes = running_processes.lock().await;
1707→        processes.insert(run_id, RunHandle::Container(container_id.clone()));
1708→    }
1709→
1710→    // Stream logs with timeout
1711→    let mut all_output = String::new();
1712→    let timeout_duration = tokio::time::Duration::from_secs(timeout_secs);
1713→
1714→    let stream_result = tokio::time::timeout(timeout_duration, async {
1715→        while let Some(line) = line_rx.recv().await {
1716→            all_output.push_str(&line);
1717→            all_output.push('\n');
1718→
1719→            // Parse progress — same logic as local
1720→            if let Some(event) = try_parse_phase_event(&line) {
1721→                process_phase_event(&event, run_id, db, tx).await;
1722→                continue;
1723→            }
1724→            if let Some(progress) = try_parse_progress(&line) {
1725→                if let Err(e) = db
1726→                    .update_pipeline_progress(run_id, progress.phase_count, progress.phase, progress.iteration)
1727→                    .await
1728→                {
1729→                    broadcast_message(
1730→                        tx,
1731→                        &WsMessage::PipelineError {
1732→                            run_id,
1733→                            message: format!("Failed to update pipeline progress: {:#}", e),
1734→                        },
1735→                    );
1736→                }
1737→
1738→                let percent = compute_percent(&progress);
1739→                broadcast_message(
1740→                    tx,
1741→                    &WsMessage::PipelineProgress {
1742→                        run_id,
1743→                        phase: progress.phase.unwrap_or(0),
1744→                        iteration: progress.iteration.unwrap_or(0),
1745→                        percent,
1746→                    },
1747→                );
1748→            }
1749→        }
1750→    })
1751→    .await;
1752→
1753→    // Handle timeout
1754→    if stream_result.is_err() {
1755→        sandbox.stop(&container_id).await?;
1756→        anyhow::bail!("Pipeline exceeded time limit ({}s)", timeout_secs);
1757→    }
1758→
1759→    // Wait for container to finish and check result
1760→    let exit_code = match sandbox.wait(&container_id).await {
1761→        Ok(code) => code,
1762→        Err(e) => {
1763→            eprintln!("[pipeline] Failed to wait for container {container_id}: {e}");
1764→            -1
1765→        }
1766→    };
1767→
1768→    // Check for OOM
1769→    if let Ok(inspect) = sandbox.inspect(&container_id).await
1770→        && let Some(state) = inspect.state
1771→        && state.oom_killed.unwrap_or(false)
1772→    {
1773→        sandbox.stop(&container_id).await?;
1774→        anyhow::bail!("Pipeline exceeded memory limit ({})", config.memory);
1775→    }
1776→
1777→    // Clean up the container
1778→    sandbox.stop(&container_id).await?;
1779→
1780→    if exit_code == 0 {
1781→        let summary = if all_output.len() > 500 {
1782→            format!("...{}", &all_output[all_output.len() - 500..])
1783→        } else {
1784→            all_output
1785→        };
1786→        Ok(summary)
1787→    } else {
1788→        anyhow::bail!("Pipeline container exited with code: {}", exit_code)
1789→    }
1790→}
1791→
1792→/// Attempt to parse a line as progress JSON.
1793→/// Accepts lines like: `{"phase": 2, "phase_count": 5, "iteration": 3}`
1794→/// Also handles lines that contain JSON embedded after a prefix (e.g., `[progress] {...}`).
1795→fn try_parse_progress(line: &str) -> Option<ProgressInfo> {
1796→    let trimmed = line.trim();
1797→
1798→    // Try direct parse first
1799→    if let Ok(info) = serde_json::from_str::<ProgressInfo>(trimmed)
1800→        && (info.phase.is_some() || info.phase_count.is_some() || info.iteration.is_some())
1801→    {
1802→        return Some(info);
1803→    }
1804→
1805→    // Try to find JSON object embedded in the line
1806→    if let Some(start) = trimmed.find('{')
1807→        && let Some(end) = trimmed.rfind('}')
1808→        && end > start
1809→    {
1810→        let json_str = &trimmed[start..=end];
