2395→            .start_run(run.id, &issue, db.clone(), tx)
2396→            .await
2397→            .unwrap();
2398→
2399→        // Poll until the process is cleaned up (planner fallback + pipeline execution)
2400→        let mut cleaned = false;
2401→        for _ in 0..100 {
2402→            tokio::time::sleep(tokio::time::Duration::from_millis(100)).await;
2403→            let processes = runner.running_processes.lock().await;
2404→            if !processes.contains_key(&run.id) {
2405→                cleaned = true;
2406→                break;
2407→            }
2408→        }
2409→        assert!(
2410→            cleaned,
2411→            "Process should be removed after completion within 10 seconds"
2412→        );
2413→
2414→        // Clean up
2415→        unsafe { std::env::remove_var("CLAUDE_CMD") };
2416→    }
