2487→            .await
2488→            .unwrap();
2489→        let run = db.create_pipeline_run(issue.id).await.unwrap();
2490→        let team = db
2491→            .create_agent_team(
2492→                run.id,
2493→                &ExecutionStrategy::Parallel,
2494→                &IsolationStrategy::Worktree,
2495→                "test reasoning",
2496→            )
2497→            .await
2498→            .unwrap();
2499→
2500→        // Create two tasks: wave 0 and wave 1
2501→        let task_w0 = db
2502→            .create_agent_task(
2503→                team.id,
2504→                "task-w0",
2505→                "wave 0 task",
2506→                &AgentRole::Coder,
2507→                0,
2508→                &[],
2509→                &IsolationStrategy::Shared,
2510→            )
2511→            .await
2512→            .unwrap();
2513→        let task_w1 = db
2514→            .create_agent_task(
2515→                team.id,
2516→                "task-w1",
2517→                "wave 1 task",
2518→                &AgentRole::Coder,
2519→                1,
2520→                &[],
2521→                &IsolationStrategy::Shared,
2522→            )
2523→            .await
2524→            .unwrap();
2525→
2526→        // Set wave 0 task to Failed
2527→        db.update_agent_task_status(task_w0.id, &AgentTaskStatus::Failed, Some("test error")).await?;
2528→
2529→        // Verify wave 1 task is still Pending (never started)
2530→        let task_w1_updated = db.get_agent_task(task_w1.id).await?;
2531→        assert_eq!(task_w1_updated.status, AgentTaskStatus::Pending);
2532→        assert!(
2533→            task_w1_updated.started_at.is_none(),
2534→            "Wave 1 task should not have been started"
2535→        );
2536→
2537→        // Verify the failed task has its error recorded
2538→        let task_w0_updated = db.get_agent_task(task_w0.id).await?;
2539→        assert_eq!(task_w0_updated.status, AgentTaskStatus::Failed);
2540→        assert_eq!(task_w0_updated.error.as_deref(), Some("test error"));
2541→
2542→        Ok(())
2543→    }
