2662→    #[tokio::test]
2663→    async fn test_git_lock_map_serializes_access() {
2664→        use std::sync::atomic::{AtomicU32, Ordering};
2665→        let map = GitLockMap::default();
2666→        let counter = Arc::new(AtomicU32::new(0));
2667→        let max_concurrent = Arc::new(AtomicU32::new(0));
2668→
2669→        let mut handles = vec![];
2670→        for _ in 0..5 {
2671→            let map = map.clone();
2672→            let counter = counter.clone();
2673→            let max_concurrent = max_concurrent.clone();
2674→            handles.push(tokio::spawn(async move {
2675→                let lock = map.get("/tmp/serialize-test").await;
2676→                let _guard = lock.lock().await;
2677→                let current = counter.fetch_add(1, Ordering::SeqCst) + 1;
2678→                max_concurrent.fetch_max(current, Ordering::SeqCst);
2679→                tokio::time::sleep(tokio::time::Duration::from_millis(10)).await;
2680→                counter.fetch_sub(1, Ordering::SeqCst);
2681→            }));
2682→        }
2683→        for h in handles {
2684→            h.await.unwrap();
2685→        }
2686→        assert_eq!(max_concurrent.load(Ordering::SeqCst), 1);
2687→    }
