//! Sequential phase orchestration — `forge run` and `forge phase <N>`.

use anyhow::{Context, Result};
use std::path::PathBuf;

use super::super::Cli;

pub fn check_run_prerequisites(project_dir: &std::path::Path) -> Result<()> {
    use forge::init::{has_phases, is_initialized};

    if !is_initialized(project_dir) {
        anyhow::bail!(
            "Project not initialized. Run 'forge init' first, then 'forge generate' to create phases."
        );
    }
    if !has_phases(project_dir) {
        anyhow::bail!(
            "No phases found. Run 'forge generate' first to create phases from your spec."
        );
    }
    Ok(())
}

pub async fn run_orchestrator(
    cli: &Cli,
    project_dir: PathBuf,
    start_phase: Option<String>,
) -> Result<()> {
    use forge::audit::{AuditLogger, FileChangeSummary, PhaseAudit, PhaseOutcome, RunConfig};
    use forge::compaction::{
        CompactionManager, DEFAULT_MODEL_WINDOW_CHARS, extract_output_summary,
    };
    use forge::config::Config;
    use forge::forge_config::{ForgeToml, PermissionMode};
    use forge::gates::{
        ApprovalGate, AutonomousGateStrategy, GateDecision, IterationDecision, ProgressTracker,
    };
    use forge::hooks::{HookAction, HookManager};
    use forge::init::get_forge_dir;
    use forge::orchestrator::{ClaudeRunner, IterationFeedback, PromptContext, StateManager};
    use forge::phase::load_phases_or_default;
    use forge::tracker::GitTracker;
    use forge::ui::OrchestratorUI;

    check_run_prerequisites(&project_dir)
        .context("Failed to check run prerequisites")?;

    let config = Config::new(
        project_dir.clone(),
        cli.verbose,
        cli.auto_approve_threshold,
        cli.spec_file.clone(),
    )
    .context("Failed to create project configuration")?;
    config.ensure_directories()
        .context("Failed to ensure project directories")?;

    // Initialize hook manager
    let mut hook_manager = HookManager::new(&project_dir, cli.verbose)
        .context("Failed to initialize hook manager")?;

    // Merge hooks from forge.toml if it exists
    let forge_dir = get_forge_dir(&project_dir);
    if let Ok(toml) = ForgeToml::load_or_default(&forge_dir)
        && !toml.hooks.definitions.is_empty()
    {
        hook_manager.merge_config(toml.hooks.into_hooks_config());
    }

    // Report hook count if any
    let hook_count = hook_manager.hook_count();
    if hook_count > 0 && cli.verbose {
        println!("Loaded {} hook(s)", hook_count);
    }

    let state = StateManager::new(config.state_file.clone());
    let tracker = GitTracker::new(&config.project_dir)?;
    let runner = ClaudeRunner::new(config.clone());
    let mut audit = AuditLogger::new(&config.audit_dir);
    let mut gate = ApprovalGate::new(cli.auto_approve_threshold, cli.yes);

    // Determine starting phase
    let start = resolve_start_phase(
        start_phase.as_deref(),
        state.get_last_completed_phase().as_deref(),
    );

    // Load phases from phases.json if it exists, otherwise use defaults
    let all_phases = load_phases_or_default(Some(&config.phases_file))?;

    // Apply permission modes from config to each phase
    let forge_toml = ForgeToml::load_or_default(&forge_dir)?;
    let phases: Vec<_> = all_phases
        .into_iter()
        .filter(|p| p.number.as_str() >= start.as_str())
        .map(|mut p| {
            // Get phase settings from config (includes pattern-matched overrides)
            let settings = forge_toml.phase_settings(&p.name);
            // Apply permission mode from config if phase doesn't have one explicitly set
            // (phases.json can override with explicit permission_mode)
            if p.permission_mode == PermissionMode::Standard {
                p.permission_mode = settings.permission_mode;
            }
            // Budget is not overridden from config — phases.json is the primary source.
            p
        })
        .collect();
    // Create autonomous gate strategy if enabled (config or CLI flag)
    let autonomy_enabled = forge_toml.autonomy.enabled || cli.autonomous;
    let mut autonomous_strategy = if autonomy_enabled {
        Some(AutonomousGateStrategy::new(
            forge_toml.autonomy.stale_iterations_before_pivot,
            forge_toml.autonomy.pivot_prompt.clone(),
        ))
    } else {
        None
    };

    let ui = std::sync::Arc::new(OrchestratorUI::new(phases.len() as u64, cli.verbose));

    // Start audit run
    audit.start_run(RunConfig {
        auto_approve_threshold: cli.auto_approve_threshold,
        skip_permissions: config.skip_permissions,
        verbose: cli.verbose,
        spec_file: config.spec_file.clone(),
        project_dir: config.project_dir.clone(),
    })?;

    let mut previous_changes: Option<FileChangeSummary> = None;

    for phase in phases {
        // Run OnApproval hooks first (can auto-approve/reject)
        let approval_result = hook_manager
            .run_on_approval(&phase, previous_changes.as_ref())
            .await?;

        let decision = match approval_result.action {
            HookAction::Approve => {
                if cli.verbose {
                    println!(
                        "  {} (hook auto-approved)",
                        console::style("Auto-approved").dim()
                    );
                }
                GateDecision::Approved
            }
            HookAction::Reject => {
                if let Some(msg) = &approval_result.message {
                    println!("  Hook rejected: {}", msg);
                }
                GateDecision::Rejected
            }
            HookAction::Block => {
                if let Some(msg) = &approval_result.message {
                    println!("  Hook blocked: {}", msg);
                }
                audit.finish_run()?;
                return Ok(());
            }
            _ => {
                if autonomous_strategy.is_some() {
                    // Autonomous mode: auto-approve all phases
                    GateDecision::Approved
                } else {
                    // Interactive: use normal approval gate
                    gate.check_phase(&phase, previous_changes.as_ref(), &ui)?
                }
            }
        };

        match decision {
            GateDecision::Aborted => {
                println!("Orchestrator aborted by user");
                audit.finish_run()?;
                return Ok(());
            }
            GateDecision::Rejected => {
                println!("Phase {} skipped", phase.number);
                continue;
            }
            GateDecision::Approved | GateDecision::ApprovedAll => {}
        }

        // Run PrePhase hooks
        let pre_phase_result = hook_manager
            .run_pre_phase(&phase, previous_changes.as_ref())
            .await?;

        match pre_phase_result.action {
            HookAction::Block => {
                if let Some(msg) = &pre_phase_result.message {
                    println!("  PrePhase hook blocked: {}", msg);
                }
                audit.finish_run()?;
                return Ok(());
            }
            HookAction::Skip => {
                if let Some(msg) = &pre_phase_result.message {
                    println!("  PrePhase hook skipped phase: {}", msg);
                }
                continue;
            }
            _ => {}
        }

        ui.start_phase(&phase.number, &phase.name);
        state.save(&phase.number, 0, "started")?;

        let mut phase_audit = PhaseAudit::new(&phase.number, &phase.name, &phase.promise);

        // Take git snapshot before phase
        let snapshot_sha = tracker.snapshot_before(&phase.number)?;

        // Initialize progress tracker for autonomous mode
        let mut progress_tracker = ProgressTracker::new();

        // Initialize compaction manager for this phase
        let context_limit = cli
            .context_limit
            .clone()
            .unwrap_or_else(|| forge_toml.phase_settings(&phase.name).context_limit);
        let mut compaction_manager = CompactionManager::new(
            &phase.number,
            &phase.name,
            &phase.promise,
            &context_limit,
            DEFAULT_MODEL_WINDOW_CHARS,
        );

        // Track current prompt context (compaction summary if any)
        let mut current_prompt_context: Option<PromptContext> = None;

        // Session continuity: track active session ID for --resume across iterations
        let mut active_session_id: Option<String> = None;
        // Iteration feedback: track feedback to inject via --append-system-prompt
        let mut previous_feedback: Option<String> = None;

        // Check if session continuity and iteration feedback are enabled
        let session_continuity_enabled = forge_toml.claude.session_continuity;
        let iteration_feedback_enabled = forge_toml.claude.iteration_feedback;

        let mut completed = false;
        let mut phase_aborted = false;
        // Accumulators for budget-exhaustion diagnostics
        let mut total_blockers_raised: usize = 0;
        let mut any_progress_signaled = false;
        let mut total_pivots: usize = 0;
        for iter in 1..=phase.budget {
            // === AUTONOMOUS MODE: Check progress before continuing ===
            if phase.permission_mode == PermissionMode::Autonomous && iter > 1 {
                if let Some(ref mut auto_strategy) = autonomous_strategy {
                    let pivot_was_issued = auto_strategy.stale_handler.pivot_issued;
                    match auto_strategy.check_stale_progress(&phase, &mut progress_tracker) {
                        IterationDecision::StopPhase => {
                            println!("  Phase stopped: no progress after pivot");
                            break;
                        }
                        IterationDecision::Continue
                            if !pivot_was_issued && auto_strategy.stale_handler.pivot_issued =>
                        {
                            // Pivot was just issued — inject prompt
                            previous_feedback = Some(auto_strategy.pivot_prompt().to_string());
                        }
                        _ => {}
                    }
                } else if !gate.check_autonomous_progress(&progress_tracker) {
                    // Interactive fallback
                    match gate.prompt_no_progress()? {
                        IterationDecision::Continue => {
                            progress_tracker.stale_iterations = 0;
                        }
                        IterationDecision::StopPhase => {
                            println!("  Phase stopped due to no progress");
                            break;
                        }
                        IterationDecision::Abort => {
                            println!("  Orchestrator aborted by user");
                            phase_aborted = true;
                            break;
                        }
                        IterationDecision::Skip => {
                            continue;
                        }
                    }
                }
            }

            // Run PreIteration hooks
            let pre_iter_result = hook_manager.run_pre_iteration(&phase, iter).await?;

            match pre_iter_result.action {
                HookAction::Block => {
                    if let Some(msg) = &pre_iter_result.message {
                        println!("  PreIteration hook blocked: {}", msg);
                    }
                    break;
                }
                HookAction::Skip => {
                    if let Some(msg) = &pre_iter_result.message {
                        println!("  PreIteration hook skipped iteration: {}", msg);
                    }
                    continue;
                }
                _ => {}
            }

            ui.start_iteration(iter, phase.budget);

            // Check if compaction is needed before this iteration
            if let Some(summary_text) = compaction_manager.compact_if_needed() {
                if cli.verbose {
                    println!("  Context compacted: {}", compaction_manager.status());
                }
                // Record compaction in audit
                if let Some(compaction) = compaction_manager.last_compaction() {
                    phase_audit.add_compaction_event(
                        compaction.iterations_summarized,
                        compaction.original_chars,
                        compaction.summary_chars,
                    );
                }
                current_prompt_context = Some(PromptContext::with_compaction(summary_text));
                // Reset session on compaction — the compacted context replaces history
                active_session_id = None;
                previous_feedback = None;
            }

            // Run iteration with optional compaction context, session resumption, and feedback
            let result = runner
                .run_iteration_with_context(
                    &phase,
                    iter,
                    Some(ui.clone()),
                    current_prompt_context.as_ref(),
                    if session_continuity_enabled {
                        active_session_id.as_deref()
                    } else {
                        None
                    },
                    if iteration_feedback_enabled {
                        previous_feedback.as_deref()
                    } else {
                        None
                    },
                )
                .await?;

            // Compute changes
            let changes = tracker.compute_changes(&snapshot_sha)?;
            ui.update_files(&changes);

            // === READONLY MODE: Validate no modifications ===
            if phase.permission_mode == PermissionMode::Readonly
                && let Err(e) = gate.validate_readonly_changes(&phase, &changes)
            {
                println!("  {} {}", console::style("Error:").red().bold(), e);
                ui.phase_failed(&phase.number, "readonly mode violation");
                phase_audit.finish(
                    PhaseOutcome::Error {
                        message: e.to_string(),
                    },
                    changes.clone(),
                );
                break;
            }

            // Show individual file changes
            for path in &changes.files_added {
                ui.show_file_change(path, forge::audit::ChangeType::Added);
            }
            for path in &changes.files_modified {
                ui.show_file_change(path, forge::audit::ChangeType::Modified);
            }

            // Accumulate cross-iteration signal diagnostics for budget-exhaustion reporting
            total_blockers_raised += result.signals.blockers.len();
            if result.signals.latest_progress().is_some() {
                any_progress_signaled = true;
            }
            total_pivots += result.signals.pivots.len();

            // Update progress tracker for autonomous mode
            let progress_pct = result.signals.latest_progress();
            progress_tracker.update(&changes, progress_pct);

            // Capture session ID for --resume in next iteration
            if let Some(ref sid) = result.session.session_id {
                active_session_id = Some(sid.clone());
            }

            // Build iteration feedback for next iteration
            previous_feedback = IterationFeedback::new()
                .with_iteration_status(iter, phase.budget, result.promise_found)
                .with_git_changes(&changes)
                .with_signals(&result.signals)
                .build();

            // Record iteration in compaction manager
            let output_summary = extract_output_summary(&result.output, 100);
            compaction_manager.record_iteration(
                iter,
                result.session.prompt_chars,
                result.session.output_chars,
                &changes,
                &result.signals,
                &output_summary,
            );

            // Show context status in verbose mode
            if cli.verbose && iter > 1 {
                println!("  {}", compaction_manager.status());
            }

            // Run PostIteration hooks with signals
            let post_iter_result = hook_manager
                .run_post_iteration_with_signals(
                    &phase,
                    iter,
                    &changes,
                    result.promise_found,
                    Some(&result.output),
                    &result.signals,
                )
                .await?;

            // Handle blockers - pause and prompt user if there are unacknowledged blockers
            if result.signals.has_unacknowledged_blockers() {
                let blockers = result.signals.unacknowledged_blockers();
                for blocker in &blockers {
                    ui.show_blocker(&blocker.description);
                }

                // Auto-continue if --yes flag is set
                let continue_anyway = if cli.yes {
                    println!(
                        "  {} {} blocker(s) detected, auto-continuing (--yes flag)",
                        console::style("⚠").yellow(),
                        blockers.len()
                    );
                    true
                } else {
                    // Prompt user about blockers
                    use dialoguer::Confirm;
                    match Confirm::new()
                        .with_prompt(format!(
                            "{} blocker(s) detected. Continue anyway?",
                            blockers.len()
                        ))
                        .default(false)
                        .interact()
                    {
                        Ok(answer) => answer,
                        Err(e) => {
                            eprintln!(
                                "Warning: Could not display blocker confirmation dialog: {}. \
                                 Stopping. Re-run with --yes to auto-continue past blockers.",
                                e
                            );
                            false
                        }
                    }
                };

                if !continue_anyway {
                    ui.phase_failed(&phase.number, "User stopped due to blockers");
                    phase_audit.finish(PhaseOutcome::UserAborted, changes.clone());
                    break;
                }
            }

            // PostIteration hook can override promise detection
            let should_complete = match post_iter_result.action {
                HookAction::Block => {
                    if let Some(msg) = &post_iter_result.message {
                        println!("  PostIteration hook blocked: {}", msg);
                    }
                    false
                }
                _ => result.promise_found,
            };

            if should_complete {
                ui.iteration_success(iter);
                phase_audit.finish(PhaseOutcome::Completed { iteration: iter }, changes.clone());
                state.save(&phase.number, iter, "completed")?;
                previous_changes = Some(changes);
                completed = true;
                break;
            } else {
                // Show progress if available
                if let Some(pct) = result.signals.latest_progress() {
                    ui.iteration_bar_message(iter, phase.budget, &format!("{}% done", pct));
                }
                ui.iteration_continue(iter);
            }

            tokio::time::sleep(tokio::time::Duration::from_secs(2)).await;
        }

        // Handle phase abort (exit orchestrator entirely)
        if phase_aborted {
            audit.finish_run()?;
            return Ok(());
        }

        if !completed {
            let changes = tracker.compute_changes(&snapshot_sha)?;

            // Run OnFailure hooks
            let failure_result = hook_manager
                .run_on_failure(&phase, phase.budget, &changes)
                .await?;

            if let Some(msg) = &failure_result.message {
                println!("  OnFailure hook: {}", msg);
            }

            phase_audit.finish(PhaseOutcome::MaxIterationsReached, changes);
            state.save(&phase.number, phase.budget, "max_iterations")?;
            ui.phase_failed(&phase.number, "max iterations reached");

            // Actionable budget-exhaustion summary
            println!();
            println!(
                "  {} Phase '{}' exhausted its budget of {} iteration(s) without emitting the promise tag '{}'.",
                console::style("Budget exhausted:").red().bold(),
                phase.name,
                phase.budget,
                phase.promise,
            );
            // Summarize what signals were observed across the whole phase
            let progress_note = if any_progress_signaled {
                "progress was signaled at least once".to_string()
            } else {
                "no <progress> signals were ever emitted".to_string()
            };
            let blockers_note = blocker_note(total_blockers_raised);
            let pivots_note = pivot_note(total_pivots);
            println!("  Summary: {progress_note}; {blockers_note}; {pivots_note}.");
            println!(
                "  Tip: Verify the promise tag in your phases config matches exactly \
                (case-sensitive). Run 'forge audit --last' to inspect Claude's raw output."
            );
            println!(
                "  Tip: Use <progress>N%</progress> and <blocker>reason</blocker> tags \
                in your phase prompt to help diagnose stuck phases."
            );
        } else {
            // Run PostPhase hooks
            let post_phase_result = hook_manager
                .run_post_phase(
                    &phase,
                    phase.budget,
                    previous_changes
                        .as_ref()
                        .unwrap_or(&FileChangeSummary::default()),
                    true,
                )
                .await?;

            if let Some(msg) = &post_phase_result.message
                && cli.verbose
            {
                println!("  PostPhase hook: {}", msg);
            }

            ui.phase_complete(&phase.number);
        }

        audit.add_phase(phase_audit)?;

        tokio::time::sleep(tokio::time::Duration::from_secs(5)).await;
    }

    let run_file = audit.finish_run()?;
    println!("Audit log saved to: {}", run_file.display());

    Ok(())
}

/// Build a human-readable note for the number of blockers raised during a phase.
///
/// Returns a string like "3 blockers raised" or "no blockers raised".
/// This is pure logic that can be unit-tested without external processes.
pub fn blocker_note(total_blockers_raised: usize) -> String {
    if total_blockers_raised > 0 {
        format!(
            "{} blocker{} raised",
            total_blockers_raised,
            if total_blockers_raised == 1 { "" } else { "s" }
        )
    } else {
        "no blockers raised".to_string()
    }
}

/// Build a human-readable note for the number of pivots signaled during a phase.
///
/// Returns a string like "2 pivots signaled" or "no pivots signaled".
/// This is pure logic that can be unit-tested without external processes.
pub fn pivot_note(total_pivots: usize) -> String {
    if total_pivots > 0 {
        format!(
            "{} pivot{} signaled",
            total_pivots,
            if total_pivots == 1 { "" } else { "s" }
        )
    } else {
        "no pivots signaled".to_string()
    }
}

/// Resolve the phase start string from an optional user-supplied value and
/// last-completed state.
///
/// - If `start_phase` is `Some(s)`, that string is returned directly.
/// - Otherwise the next phase after `last_completed` is returned (zero-padded
///   to two digits), falling back to `"01"` when nothing has been completed.
///
/// This is pure logic that can be unit-tested without external processes.
pub fn resolve_start_phase(start_phase: Option<&str>, last_completed: Option<&str>) -> String {
    start_phase.map(|s| s.to_string()).unwrap_or_else(|| {
        last_completed
            .map(|p| format!("{:02}", p.parse::<u32>().unwrap_or(0) + 1))
            .unwrap_or_else(|| "01".to_string())
    })
}

pub async fn run_single_phase(cli: &Cli, project_dir: PathBuf, phase_num: &str) -> Result<()> {
    use forge::init::get_forge_dir;
    use forge::phase::PhasesFile;

    check_run_prerequisites(&project_dir)?;

    // Load phases from phases.json
    let forge_dir = get_forge_dir(&project_dir);
    let phases_file = forge_dir.join("phases.json");
    let pf = PhasesFile::load(&phases_file)?;

    let phase = pf
        .phases
        .into_iter()
        .find(|p| p.number == phase_num)
        .ok_or_else(|| anyhow::anyhow!("Unknown phase: {}", phase_num))?;

    run_orchestrator(cli, project_dir, Some(phase.number)).await
}

#[cfg(test)]
mod tests {
    use super::*;

    // ── blocker_note ──────────────────────────────────────────────────────────

    #[test]
    fn blocker_note_zero_returns_no_blockers() {
        assert_eq!(blocker_note(0), "no blockers raised");
    }

    #[test]
    fn blocker_note_one_is_singular() {
        let note = blocker_note(1);
        assert_eq!(note, "1 blocker raised");
        assert!(note.contains('1'), "expected count in note: {note}");
        assert!(
            note.contains("blocker"),
            "expected 'blocker' in note: {note}"
        );
        // Must NOT contain the plural suffix "s" (right after "blocker")
        assert!(
            !note.contains("blockers"),
            "note should be singular: {note}"
        );
    }

    #[test]
    fn blocker_note_many_is_plural() {
        let note = blocker_note(3);
        assert_eq!(note, "3 blockers raised");
        assert!(note.contains('3'), "expected count in note: {note}");
        assert!(note.contains("blockers"), "expected plural in note: {note}");
    }

    // ── pivot_note ────────────────────────────────────────────────────────────

    #[test]
    fn pivot_note_zero_returns_no_pivots() {
        assert_eq!(pivot_note(0), "no pivots signaled");
    }

    #[test]
    fn pivot_note_one_is_singular() {
        let note = pivot_note(1);
        assert_eq!(note, "1 pivot signaled");
        assert!(note.contains('1'), "expected count in note: {note}");
        assert!(note.contains("pivot"), "expected 'pivot' in note: {note}");
        assert!(!note.contains("pivots"), "note should be singular: {note}");
    }

    #[test]
    fn pivot_note_many_is_plural() {
        let note = pivot_note(5);
        assert_eq!(note, "5 pivots signaled");
        assert!(note.contains('5'), "expected count in note: {note}");
        assert!(note.contains("pivots"), "expected plural in note: {note}");
    }

    // ── resolve_start_phase ───────────────────────────────────────────────────

    #[test]
    fn resolve_start_phase_explicit_overrides_state() {
        // User explicitly requested phase "03"; last completed was "02"
        let result = resolve_start_phase(Some("03"), Some("02"));
        assert_eq!(result, "03");
    }

    #[test]
    fn resolve_start_phase_derives_next_from_last_completed() {
        // No explicit start; last completed is "04" → next is "05"
        let result = resolve_start_phase(None, Some("04"));
        assert_eq!(result, "05");
    }

    #[test]
    fn resolve_start_phase_zero_pads_single_digit() {
        // Last completed "1" → next is "02"
        let result = resolve_start_phase(None, Some("1"));
        assert_eq!(result, "02");
    }

    #[test]
    fn resolve_start_phase_falls_back_to_01_when_nothing_completed() {
        let result = resolve_start_phase(None, None);
        assert_eq!(result, "01");
    }

    #[test]
    fn resolve_start_phase_handles_non_numeric_last_completed_gracefully() {
        // parse::<u32>() fails → treated as 0 → next is "01"
        let result = resolve_start_phase(None, Some("abc"));
        assert_eq!(result, "01");
    }

    // ── check_run_prerequisites ───────────────────────────────────────────────

    #[test]
    fn check_run_prerequisites_fails_on_uninitialized_directory() {
        let tmp = tempfile::tempdir().expect("tempdir");
        let err = check_run_prerequisites(tmp.path()).unwrap_err();
        let msg = err.to_string();
        assert!(
            msg.contains("forge init"),
            "expected 'forge init' hint in error: {msg}"
        );
    }
}

//! Sequential phase orchestration — `forge run` and `forge phase <N>`.

use anyhow::{Context, Result};
use std::path::PathBuf;

use super::super::Cli;

pub fn check_run_prerequisites(project_dir: &std::path::Path) -> Result<()> {
    use forge::init::{has_phases, is_initialized};

    if !is_initialized(project_dir) {
        anyhow::bail!(
            "Project not initialized. Run 'forge init' first, then 'forge generate' to create phases."
        );
    }
    if !has_phases(project_dir) {
        anyhow::bail!(
            "No phases found. Run 'forge generate' first to create phases from your spec."
        );
    }
    Ok(())
}

pub async fn run_orchestrator(
    cli: &Cli,
    project_dir: PathBuf,
    start_phase: Option<String>,
) -> Result<()> {
    use forge::audit::{AuditLogger, FileChangeSummary, PhaseAudit, PhaseOutcome, RunConfig};
    use forge::compaction::{
        CompactionManager, DEFAULT_MODEL_WINDOW_CHARS, extract_output_summary,
    };
    use forge::config::Config;
    use forge::forge_config::{ForgeToml, PermissionMode};
    use forge::gates::{
        ApprovalGate, AutonomousGateStrategy, GateDecision, IterationDecision, ProgressTracker,
    };
    use forge::hooks::{HookAction, HookManager};
    use forge::init::get_forge_dir;
    use forge::orchestrator::{ClaudeRunner, IterationFeedback, PromptContext, StateManager};
    use forge::phase::load_phases_or_default;
    use forge::tracker::GitTracker;
    use forge::ui::OrchestratorUI;

    check_run_prerequisites(&project_dir)
        .context("Failed to check run prerequisites")?;

    let config = Config::new(
        project_dir.clone(),
        cli.verbose,
        cli.auto_approve_threshold,
        cli.spec_file.clone(),
    )
    .context("Failed to create project configuration")?;
    config.ensure_directories()
        .context("Failed to ensure project directories")?;

    // Initialize hook manager
    let mut hook_manager = HookManager::new(&project_dir, cli.verbose)
        .context("Failed to initialize hook manager")?;

    // Merge hooks from forge.toml if it exists
    let forge_dir = get_forge_dir(&project_dir);
    if let Ok(toml) = ForgeToml::load_or_default(&forge_dir)
        && !toml.hooks.definitions.is_empty()
    {
        hook_manager.merge_config(toml.hooks.into_hooks_config());
    }

    // Report hook count if any
    let hook_count = hook_manager.hook_count();
    if hook_count > 0 && cli.verbose {
        println!("Loaded {} hook(s)", hook_count);
    }

    let state = StateManager::new(config.state_file.clone());
    let tracker = GitTracker::new(&config.project_dir)
        .context("Failed to initialize git tracker")?;
    let runner = ClaudeRunner::new(config.clone());
    let mut audit = AuditLogger::new(&config.audit_dir);
    let mut gate = ApprovalGate::new(cli.auto_approve_threshold, cli.yes);

    // Determine starting phase
    let start = resolve_start_phase(
        start_phase.as_deref(),
        state.get_last_completed_phase().as_deref(),
    );

    // Load phases from phases.json if it exists, otherwise use defaults
    let all_phases = load_phases_or_default(Some(&config.phases_file))?;

    // Apply permission modes from config to each phase
    let forge_toml = ForgeToml::load_or_default(&forge_dir)?;
    let phases: Vec<_> = all_phases
        .into_iter()
        .filter(|p| p.number.as_str() >= start.as_str())
        .map(|mut p| {
            // Get phase settings from config (includes pattern-matched overrides)
            let settings = forge_toml.phase_settings(&p.name);
            // Apply permission mode from config if phase doesn't have one explicitly set
            // (phases.json can override with explicit permission_mode)
            if p.permission_mode == PermissionMode::Standard {
                p.permission_mode = settings.permission_mode;
            }
            // Budget is not overridden from config — phases.json is the primary source.
            p
        })
        .collect();
    // Create autonomous gate strategy if enabled (config or CLI flag)
    let autonomy_enabled = forge_toml.autonomy.enabled || cli.autonomous;
    let mut autonomous_strategy = if autonomy_enabled {
        Some(AutonomousGateStrategy::new(
            forge_toml.autonomy.stale_iterations_before_pivot,
            forge_toml.autonomy.pivot_prompt.clone(),
        ))
    } else {
        None
    };

    let ui = std::sync::Arc::new(OrchestratorUI::new(phases.len() as u64, cli.verbose));

    // Start audit run
    audit.start_run(RunConfig {
        auto_approve_threshold: cli.auto_approve_threshold,
        skip_permissions: config.skip_permissions,
        verbose: cli.verbose,
        spec_file: config.spec_file.clone(),
        project_dir: config.project_dir.clone(),
    })?;

    let mut previous_changes: Option<FileChangeSummary> = None;

    for phase in phases {
        // Run OnApproval hooks first (can auto-approve/reject)
        let approval_result = hook_manager
            .run_on_approval(&phase, previous_changes.as_ref())
            .await?;

        let decision = match approval_result.action {
            HookAction::Approve => {
                if cli.verbose {
                    println!(
                        "  {} (hook auto-approved)",
                        console::style("Auto-approved").dim()
                    );
                }
                GateDecision::Approved
            }
            HookAction::Reject => {
                if let Some(msg) = &approval_result.message {
                    println!("  Hook rejected: {}", msg);
                }
                GateDecision::Rejected
            }
            HookAction::Block => {
                if let Some(msg) = &approval_result.message {
                    println!("  Hook blocked: {}", msg);
                }
                audit.finish_run()?;
                return Ok(());
            }
            _ => {
                if autonomous_strategy.is_some() {
                    // Autonomous mode: auto-approve all phases
                    GateDecision::Approved
                } else {
                    // Interactive: use normal approval gate
                    gate.check_phase(&phase, previous_changes.as_ref(), &ui)?
                }
            }
        };

        match decision {
            GateDecision::Aborted => {
                println!("Orchestrator aborted by user");
                audit.finish_run()?;
                return Ok(());
            }
            GateDecision::Rejected => {
                println!("Phase {} skipped", phase.number);
                continue;
            }
            GateDecision::Approved | GateDecision::ApprovedAll => {}
        }

        // Run PrePhase hooks
        let pre_phase_result = hook_manager
            .run_pre_phase(&phase, previous_changes.as_ref())
            .await?;

        match pre_phase_result.action {
            HookAction::Block => {
                if let Some(msg) = &pre_phase_result.message {
                    println!("  PrePhase hook blocked: {}", msg);
                }
                audit.finish_run()?;
                return Ok(());
            }
            HookAction::Skip => {
                if let Some(msg) = &pre_phase_result.message {
                    println!("  PrePhase hook skipped phase: {}", msg);
                }
                continue;
            }
            _ => {}
        }

        ui.start_phase(&phase.number, &phase.name);
        state.save(&phase.number, 0, "started")?;

        let mut phase_audit = PhaseAudit::new(&phase.number, &phase.name, &phase.promise);

        // Take git snapshot before phase
        let snapshot_sha = tracker.snapshot_before(&phase.number)?;

        // Initialize progress tracker for autonomous mode
        let mut progress_tracker = ProgressTracker::new();

        // Initialize compaction manager for this phase
        let context_limit = cli
            .context_limit
            .clone()
            .unwrap_or_else(|| forge_toml.phase_settings(&phase.name).context_limit);
        let mut compaction_manager = CompactionManager::new(
            &phase.number,
            &phase.name,
            &phase.promise,
            &context_limit,
            DEFAULT_MODEL_WINDOW_CHARS,
        );

        // Track current prompt context (compaction summary if any)
        let mut current_prompt_context: Option<PromptContext> = None;

        // Session continuity: track active session ID for --resume across iterations
        let mut active_session_id: Option<String> = None;
        // Iteration feedback: track feedback to inject via --append-system-prompt
        let mut previous_feedback: Option<String> = None;

        // Check if session continuity and iteration feedback are enabled
        let session_continuity_enabled = forge_toml.claude.session_continuity;
        let iteration_feedback_enabled = forge_toml.claude.iteration_feedback;

        let mut completed = false;
        let mut phase_aborted = false;
        // Accumulators for budget-exhaustion diagnostics
        let mut total_blockers_raised: usize = 0;
        let mut any_progress_signaled = false;
        let mut total_pivots: usize = 0;
        for iter in 1..=phase.budget {
            // === AUTONOMOUS MODE: Check progress before continuing ===
            if phase.permission_mode == PermissionMode::Autonomous && iter > 1 {
                if let Some(ref mut auto_strategy) = autonomous_strategy {
                    let pivot_was_issued = auto_strategy.stale_handler.pivot_issued;
                    match auto_strategy.check_stale_progress(&phase, &mut progress_tracker) {
                        IterationDecision::StopPhase => {
                            println!("  Phase stopped: no progress after pivot");
                            break;
                        }
                        IterationDecision::Continue
                            if !pivot_was_issued && auto_strategy.stale_handler.pivot_issued =>
                        {
                            // Pivot was just issued — inject prompt
                            previous_feedback = Some(auto_strategy.pivot_prompt().to_string());
                        }
                        _ => {}
                    }
                } else if !gate.check_autonomous_progress(&progress_tracker) {
                    // Interactive fallback
                    match gate.prompt_no_progress()? {
                        IterationDecision::Continue => {
                            progress_tracker.stale_iterations = 0;
                        }
                        IterationDecision::StopPhase => {
                            println!("  Phase stopped due to no progress");
                            break;
                        }
                        IterationDecision::Abort => {
                            println!("  Orchestrator aborted by user");
                            phase_aborted = true;
                            break;
                        }
                        IterationDecision::Skip => {
                            continue;
                        }
                    }
                }
            }

            // Run PreIteration hooks
            let pre_iter_result = hook_manager.run_pre_iteration(&phase, iter).await?;

            match pre_iter_result.action {
                HookAction::Block => {
                    if let Some(msg) = &pre_iter_result.message {
                        println!("  PreIteration hook blocked: {}", msg);
                    }
                    break;
                }
                HookAction::Skip => {
                    if let Some(msg) = &pre_iter_result.message {
                        println!("  PreIteration hook skipped iteration: {}", msg);
                    }
                    continue;
                }
                _ => {}
            }

            ui.start_iteration(iter, phase.budget);

            // Check if compaction is needed before this iteration
            if let Some(summary_text) = compaction_manager.compact_if_needed() {
                if cli.verbose {
                    println!("  Context compacted: {}", compaction_manager.status());
                }
                // Record compaction in audit
                if let Some(compaction) = compaction_manager.last_compaction() {
                    phase_audit.add_compaction_event(
                        compaction.iterations_summarized,
                        compaction.original_chars,
                        compaction.summary_chars,
                    );
                }
                current_prompt_context = Some(PromptContext::with_compaction(summary_text));
                // Reset session on compaction — the compacted context replaces history
                active_session_id = None;
                previous_feedback = None;
            }

            // Run iteration with optional compaction context, session resumption, and feedback
            let result = runner
                .run_iteration_with_context(
                    &phase,
                    iter,
                    Some(ui.clone()),
                    current_prompt_context.as_ref(),
                    if session_continuity_enabled {
                        active_session_id.as_deref()
                    } else {
                        None
                    },
                    if iteration_feedback_enabled {
                        previous_feedback.as_deref()
                    } else {
                        None
                    },
                )
                .await?;

            // Compute changes
            let changes = tracker.compute_changes(&snapshot_sha)?;
            ui.update_files(&changes);

            // === READONLY MODE: Validate no modifications ===
            if phase.permission_mode == PermissionMode::Readonly
                && let Err(e) = gate.validate_readonly_changes(&phase, &changes)
            {
                println!("  {} {}", console::style("Error:").red().bold(), e);
                ui.phase_failed(&phase.number, "readonly mode violation");
                phase_audit.finish(
                    PhaseOutcome::Error {
                        message: e.to_string(),
                    },
                    changes.clone(),
                );
                break;
            }

            // Show individual file changes
            for path in &changes.files_added {
                ui.show_file_change(path, forge::audit::ChangeType::Added);
            }
            for path in &changes.files_modified {
                ui.show_file_change(path, forge::audit::ChangeType::Modified);
            }

            // Accumulate cross-iteration signal diagnostics for budget-exhaustion reporting
            total_blockers_raised += result.signals.blockers.len();
            if result.signals.latest_progress().is_some() {
                any_progress_signaled = true;
            }
            total_pivots += result.signals.pivots.len();

            // Update progress tracker for autonomous mode
            let progress_pct = result.signals.latest_progress();
            progress_tracker.update(&changes, progress_pct);

            // Capture session ID for --resume in next iteration
            if let Some(ref sid) = result.session.session_id {
                active_session_id = Some(sid.clone());
            }

            // Build iteration feedback for next iteration
            previous_feedback = IterationFeedback::new()
                .with_iteration_status(iter, phase.budget, result.promise_found)
                .with_git_changes(&changes)
                .with_signals(&result.signals)
                .build();

            // Record iteration in compaction manager
            let output_summary = extract_output_summary(&result.output, 100);
            compaction_manager.record_iteration(
                iter,
                result.session.prompt_chars,
                result.session.output_chars,
                &changes,
                &result.signals,
                &output_summary,
            );

            // Show context status in verbose mode
            if cli.verbose && iter > 1 {
                println!("  {}", compaction_manager.status());
            }

            // Run PostIteration hooks with signals
            let post_iter_result = hook_manager
                .run_post_iteration_with_signals(
                    &phase,
                    iter,
                    &changes,
                    result.promise_found,
                    Some(&result.output),
                    &result.signals,
                )
                .await?;

            // Handle blockers - pause and prompt user if there are unacknowledged blockers
            if result.signals.has_unacknowledged_blockers() {
                let blockers = result.signals.unacknowledged_blockers();
                for blocker in &blockers {
                    ui.show_blocker(&blocker.description);
                }

                // Auto-continue if --yes flag is set
                let continue_anyway = if cli.yes {
                    println!(
                        "  {} {} blocker(s) detected, auto-continuing (--yes flag)",
                        console::style("⚠").yellow(),
                        blockers.len()
                    );
                    true
                } else {
                    // Prompt user about blockers
                    use dialoguer::Confirm;
                    match Confirm::new()
                        .with_prompt(format!(
                            "{} blocker(s) detected. Continue anyway?",
                            blockers.len()
                        ))
                        .default(false)
                        .interact()
                    {
                        Ok(answer) => answer,
                        Err(e) => {
                            eprintln!(
                                "Warning: Could not display blocker confirmation dialog: {}. \
                                 Stopping. Re-run with --yes to auto-continue past blockers.",
                                e
                            );
                            false
                        }
                    }
                };

                if !continue_anyway {
                    ui.phase_failed(&phase.number, "User stopped due to blockers");
                    phase_audit.finish(PhaseOutcome::UserAborted, changes.clone());
                    break;
                }
            }

            // PostIteration hook can override promise detection
            let should_complete = match post_iter_result.action {
                HookAction::Block => {
                    if let Some(msg) = &post_iter_result.message {
                        println!("  PostIteration hook blocked: {}", msg);
                    }
                    false
                }
                _ => result.promise_found,
            };

            if should_complete {
                ui.iteration_success(iter);
                phase_audit.finish(PhaseOutcome::Completed { iteration: iter }, changes.clone());
                state.save(&phase.number, iter, "completed")?;
                previous_changes = Some(changes);
                completed = true;
                break;
            } else {
                // Show progress if available
                if let Some(pct) = result.signals.latest_progress() {
                    ui.iteration_bar_message(iter, phase.budget, &format!("{}% done", pct));
                }
                ui.iteration_continue(iter);
            }

            tokio::time::sleep(tokio::time::Duration::from_secs(2)).await;
        }

        // Handle phase abort (exit orchestrator entirely)
        if phase_aborted {
            audit.finish_run()?;
            return Ok(());
        }

        if !completed {
            let changes = tracker.compute_changes(&snapshot_sha)?;

            // Run OnFailure hooks
            let failure_result = hook_manager
                .run_on_failure(&phase, phase.budget, &changes)
                .await?;

            if let Some(msg) = &failure_result.message {
                println!("  OnFailure hook: {}", msg);
            }

            phase_audit.finish(PhaseOutcome::MaxIterationsReached, changes);
            state.save(&phase.number, phase.budget, "max_iterations")?;
            ui.phase_failed(&phase.number, "max iterations reached");

            // Actionable budget-exhaustion summary
            println!();
            println!(
                "  {} Phase '{}' exhausted its budget of {} iteration(s) without emitting the promise tag '{}'.",
                console::style("Budget exhausted:").red().bold(),
                phase.name,
                phase.budget,
                phase.promise,
            );
            // Summarize what signals were observed across the whole phase
            let progress_note = if any_progress_signaled {
                "progress was signaled at least once".to_string()
            } else {
                "no <progress> signals were ever emitted".to_string()
            };
            let blockers_note = blocker_note(total_blockers_raised);
            let pivots_note = pivot_note(total_pivots);
            println!("  Summary: {progress_note}; {blockers_note}; {pivots_note}.");
            println!(
                "  Tip: Verify the promise tag in your phases config matches exactly \
                (case-sensitive). Run 'forge audit --last' to inspect Claude's raw output."
            );
            println!(
                "  Tip: Use <progress>N%</progress> and <blocker>reason</blocker> tags \
                in your phase prompt to help diagnose stuck phases."
            );
        } else {
            // Run PostPhase hooks
            let post_phase_result = hook_manager
                .run_post_phase(
                    &phase,
                    phase.budget,
                    previous_changes
                        .as_ref()
                        .unwrap_or(&FileChangeSummary::default()),
                    true,
                )
                .await?;

            if let Some(msg) = &post_phase_result.message
                && cli.verbose
            {
                println!("  PostPhase hook: {}", msg);
            }

            ui.phase_complete(&phase.number);
        }

        audit.add_phase(phase_audit)?;

        tokio::time::sleep(tokio::time::Duration::from_secs(5)).await;
    }

    let run_file = audit.finish_run()?;
    println!("Audit log saved to: {}", run_file.display());

    Ok(())
}

/// Build a human-readable note for the number of blockers raised during a phase.
///
/// Returns a string like "3 blockers raised" or "no blockers raised".
/// This is pure logic that can be unit-tested without external processes.
pub fn blocker_note(total_blockers_raised: usize) -> String {
    if total_blockers_raised > 0 {
        format!(
            "{} blocker{} raised",
            total_blockers_raised,
            if total_blockers_raised == 1 { "" } else { "s" }
        )
    } else {
        "no blockers raised".to_string()
    }
}

/// Build a human-readable note for the number of pivots signaled during a phase.
///
/// Returns a string like "2 pivots signaled" or "no pivots signaled".
/// This is pure logic that can be unit-tested without external processes.
pub fn pivot_note(total_pivots: usize) -> String {
    if total_pivots > 0 {
        format!(
            "{} pivot{} signaled",
            total_pivots,
            if total_pivots == 1 { "" } else { "s" }
        )
    } else {
        "no pivots signaled".to_string()
    }
}

/// Resolve the phase start string from an optional user-supplied value and
/// last-completed state.
///
/// - If `start_phase` is `Some(s)`, that string is returned directly.
/// - Otherwise the next phase after `last_completed` is returned (zero-padded
///   to two digits), falling back to `"01"` when nothing has been completed.
///
/// This is pure logic that can be unit-tested without external processes.
pub fn resolve_start_phase(start_phase: Option<&str>, last_completed: Option<&str>) -> String {
    start_phase.map(|s| s.to_string()).unwrap_or_else(|| {
        last_completed
            .map(|p| format!("{:02}", p.parse::<u32>().unwrap_or(0) + 1))
            .unwrap_or_else(|| "01".to_string())
    })
}

pub async fn run_single_phase(cli: &Cli, project_dir: PathBuf, phase_num: &str) -> Result<()> {
    use forge::init::get_forge_dir;
    use forge::phase::PhasesFile;

    check_run_prerequisites(&project_dir)?;

    // Load phases from phases.json
    let forge_dir = get_forge_dir(&project_dir);
    let phases_file = forge_dir.join("phases.json");
    let pf = PhasesFile::load(&phases_file)?;

    let phase = pf
        .phases
        .into_iter()
        .find(|p| p.number == phase_num)
        .ok_or_else(|| anyhow::anyhow!("Unknown phase: {}", phase_num))?;

    run_orchestrator(cli, project_dir, Some(phase.number)).await
}

#[cfg(test)]
mod tests {
    use super::*;

    // ── blocker_note ──────────────────────────────────────────────────────────

    #[test]
    fn blocker_note_zero_returns_no_blockers() {
        assert_eq!(blocker_note(0), "no blockers raised");
    }

    #[test]
    fn blocker_note_one_is_singular() {
        let note = blocker_note(1);
        assert_eq!(note, "1 blocker raised");
        assert!(note.contains('1'), "expected count in note: {note}");
        assert!(
            note.contains("blocker"),
            "expected 'blocker' in note: {note}"
        );
        // Must NOT contain the plural suffix "s" (right after "blocker")
        assert!(
            !note.contains("blockers"),
            "note should be singular: {note}"
        );
    }

    #[test]
    fn blocker_note_many_is_plural() {
        let note = blocker_note(3);
        assert_eq!(note, "3 blockers raised");
        assert!(note.contains('3'), "expected count in note: {note}");
        assert!(note.contains("blockers"), "expected plural in note: {note}");
    }

    // ── pivot_note ────────────────────────────────────────────────────────────

    #[test]
    fn pivot_note_zero_returns_no_pivots() {
        assert_eq!(pivot_note(0), "no pivots signaled");
    }

    #[test]
    fn pivot_note_one_is_singular() {
        let note = pivot_note(1);
        assert_eq!(note, "1 pivot signaled");
        assert!(note.contains('1'), "expected count in note: {note}");
        assert!(note.contains("pivot"), "expected 'pivot' in note: {note}");
        assert!(!note.contains("pivots"), "note should be singular: {note}");
    }

    #[test]
    fn pivot_note_many_is_plural() {
        let note = pivot_note(5);
        assert_eq!(note, "5 pivots signaled");
        assert!(note.contains('5'), "expected count in note: {note}");
        assert!(note.contains("pivots"), "expected plural in note: {note}");
    }

    // ── resolve_start_phase ───────────────────────────────────────────────────

    #[test]
    fn resolve_start_phase_explicit_overrides_state() {
        // User explicitly requested phase "03"; last completed was "02"
        let result = resolve_start_phase(Some("03"), Some("02"));
        assert_eq!(result, "03");
    }

    #[test]
    fn resolve_start_phase_derives_next_from_last_completed() {
        // No explicit start; last completed is "04" → next is "05"
        let result = resolve_start_phase(None, Some("04"));
        assert_eq!(result, "05");
    }

    #[test]
    fn resolve_start_phase_zero_pads_single_digit() {
        // Last completed "1" → next is "02"
        let result = resolve_start_phase(None, Some("1"));
        assert_eq!(result, "02");
    }

    #[test]
    fn resolve_start_phase_falls_back_to_01_when_nothing_completed() {
        let result = resolve_start_phase(None, None);
        assert_eq!(result, "01");
    }

    #[test]
    fn resolve_start_phase_handles_non_numeric_last_completed_gracefully() {
        // parse::<u32>() fails → treated as 0 → next is "01"
        let result = resolve_start_phase(None, Some("abc"));
        assert_eq!(result, "01");
    }

    // ── check_run_prerequisites ───────────────────────────────────────────────

    #[test]
    fn check_run_prerequisites_fails_on_uninitialized_directory() {
        let tmp = tempfile::tempdir().expect("tempdir");
        let err = check_run_prerequisites(tmp.path()).unwrap_err();
        let msg = err.to_string();
        assert!(
            msg.contains("forge init"),
            "expected 'forge init' hint in error: {msg}"
        );
    }
}

//! Sequential phase orchestration — `forge run` and `forge phase <N>`.

use anyhow::{Context, Result};
use std::path::PathBuf;

use super::super::Cli;

pub fn check_run_prerequisites(project_dir: &std::path::Path) -> Result<()> {
    use forge::init::{has_phases, is_initialized};

    if !is_initialized(project_dir) {
        anyhow::bail!(
            "Project not initialized. Run 'forge init' first, then 'forge generate' to create phases."
        );
    }
    if !has_phases(project_dir) {
        anyhow::bail!(
            "No phases found. Run 'forge generate' first to create phases from your spec."
        );
    }
    Ok(())
}

pub async fn run_orchestrator(
    cli: &Cli,
    project_dir: PathBuf,
    start_phase: Option<String>,
) -> Result<()> {
    use forge::audit::{AuditLogger, FileChangeSummary, PhaseAudit, PhaseOutcome, RunConfig};
    use forge::compaction::{
        CompactionManager, DEFAULT_MODEL_WINDOW_CHARS, extract_output_summary,
    };
    use forge::config::Config;
    use forge::forge_config::{ForgeToml, PermissionMode};
    use forge::gates::{
        ApprovalGate, AutonomousGateStrategy, GateDecision, IterationDecision, ProgressTracker,
    };
    use forge::hooks::{HookAction, HookManager};
    use forge::init::get_forge_dir;
    use forge::orchestrator::{ClaudeRunner, IterationFeedback, PromptContext, StateManager};
    use forge::phase::load_phases_or_default;
    use forge::tracker::GitTracker;
    use forge::ui::OrchestratorUI;

    check_run_prerequisites(&project_dir)
        .context("Failed to check run prerequisites")?;

    let config = Config::new(
        project_dir.clone(),
        cli.verbose,
        cli.auto_approve_threshold,
        cli.spec_file.clone(),
    )
    .context("Failed to create project configuration")?;
    config.ensure_directories()
        .context("Failed to ensure project directories")?;

    // Initialize hook manager
    let mut hook_manager = HookManager::new(&project_dir, cli.verbose)
        .context("Failed to initialize hook manager")?;

    // Merge hooks from forge.toml if it exists
    let forge_dir = get_forge_dir(&project_dir);
    if let Ok(toml) = ForgeToml::load_or_default(&forge_dir)
        && !toml.hooks.definitions.is_empty()
    {
        hook_manager.merge_config(toml.hooks.into_hooks_config());
    }

    // Report hook count if any
    let hook_count = hook_manager.hook_count();
    if hook_count > 0 && cli.verbose {
        println!("Loaded {} hook(s)", hook_count);
    }

    let state = StateManager::new(config.state_file.clone());
    let tracker = GitTracker::new(&config.project_dir)
        .context("Failed to initialize git tracker")?;
    let runner = ClaudeRunner::new(config.clone());
    let mut audit = AuditLogger::new(&config.audit_dir);
    let mut gate = ApprovalGate::new(cli.auto_approve_threshold, cli.yes);

    // Determine starting phase
    let start = resolve_start_phase(
        start_phase.as_deref(),
        state.get_last_completed_phase().as_deref(),
    );

    // Load phases from phases.json if it exists, otherwise use defaults
    let all_phases = load_phases_or_default(Some(&config.phases_file))
        .context("Failed to load phases")?;

    // Apply permission modes from config to each phase
    let forge_toml = ForgeToml::load_or_default(&forge_dir)?;
    let phases: Vec<_> = all_phases
        .into_iter()
        .filter(|p| p.number.as_str() >= start.as_str())
        .map(|mut p| {
            // Get phase settings from config (includes pattern-matched overrides)
            let settings = forge_toml.phase_settings(&p.name);
            // Apply permission mode from config if phase doesn't have one explicitly set
            // (phases.json can override with explicit permission_mode)
            if p.permission_mode == PermissionMode::Standard {
                p.permission_mode = settings.permission_mode;
            }
            // Budget is not overridden from config — phases.json is the primary source.
            p
        })
        .collect();
    // Create autonomous gate strategy if enabled (config or CLI flag)
    let autonomy_enabled = forge_toml.autonomy.enabled || cli.autonomous;
    let mut autonomous_strategy = if autonomy_enabled {
        Some(AutonomousGateStrategy::new(
            forge_toml.autonomy.stale_iterations_before_pivot,
            forge_toml.autonomy.pivot_prompt.clone(),
        ))
    } else {
        None
    };

    let ui = std::sync::Arc::new(OrchestratorUI::new(phases.len() as u64, cli.verbose));

    // Start audit run
    audit.start_run(RunConfig {
        auto_approve_threshold: cli.auto_approve_threshold,
        skip_permissions: config.skip_permissions,
        verbose: cli.verbose,
        spec_file: config.spec_file.clone(),
        project_dir: config.project_dir.clone(),
    })?;

    let mut previous_changes: Option<FileChangeSummary> = None;

    for phase in phases {
        // Run OnApproval hooks first (can auto-approve/reject)
        let approval_result = hook_manager
            .run_on_approval(&phase, previous_changes.as_ref())
            .await?;

        let decision = match approval_result.action {
            HookAction::Approve => {
                if cli.verbose {
                    println!(
                        "  {} (hook auto-approved)",
                        console::style("Auto-approved").dim()
                    );
                }
                GateDecision::Approved
            }
            HookAction::Reject => {
                if let Some(msg) = &approval_result.message {
                    println!("  Hook rejected: {}", msg);
                }
                GateDecision::Rejected
            }
            HookAction::Block => {
                if let Some(msg) = &approval_result.message {
                    println!("  Hook blocked: {}", msg);
                }
                audit.finish_run()?;
                return Ok(());
            }
            _ => {
                if autonomous_strategy.is_some() {
                    // Autonomous mode: auto-approve all phases
                    GateDecision::Approved
                } else {
                    // Interactive: use normal approval gate
                    gate.check_phase(&phase, previous_changes.as_ref(), &ui)?
                }
            }
        };

        match decision {
            GateDecision::Aborted => {
                println!("Orchestrator aborted by user");
                audit.finish_run()?;
                return Ok(());
            }
            GateDecision::Rejected => {
                println!("Phase {} skipped", phase.number);
                continue;
            }
            GateDecision::Approved | GateDecision::ApprovedAll => {}
        }

        // Run PrePhase hooks
        let pre_phase_result = hook_manager
            .run_pre_phase(&phase, previous_changes.as_ref())
            .await?;

        match pre_phase_result.action {
            HookAction::Block => {
                if let Some(msg) = &pre_phase_result.message {
                    println!("  PrePhase hook blocked: {}", msg);
                }
                audit.finish_run()?;
                return Ok(());
            }
            HookAction::Skip => {
                if let Some(msg) = &pre_phase_result.message {
                    println!("  PrePhase hook skipped phase: {}", msg);
                }
                continue;
            }
            _ => {}
        }

        ui.start_phase(&phase.number, &phase.name);
        state.save(&phase.number, 0, "started")?;

        let mut phase_audit = PhaseAudit::new(&phase.number, &phase.name, &phase.promise);

        // Take git snapshot before phase
        let snapshot_sha = tracker.snapshot_before(&phase.number)?;

        // Initialize progress tracker for autonomous mode
        let mut progress_tracker = ProgressTracker::new();

        // Initialize compaction manager for this phase
        let context_limit = cli
            .context_limit
            .clone()
            .unwrap_or_else(|| forge_toml.phase_settings(&phase.name).context_limit);
        let mut compaction_manager = CompactionManager::new(
            &phase.number,
            &phase.name,
            &phase.promise,
            &context_limit,
            DEFAULT_MODEL_WINDOW_CHARS,
        );

        // Track current prompt context (compaction summary if any)
        let mut current_prompt_context: Option<PromptContext> = None;

        // Session continuity: track active session ID for --resume across iterations
        let mut active_session_id: Option<String> = None;
        // Iteration feedback: track feedback to inject via --append-system-prompt
        let mut previous_feedback: Option<String> = None;

        // Check if session continuity and iteration feedback are enabled
        let session_continuity_enabled = forge_toml.claude.session_continuity;
        let iteration_feedback_enabled = forge_toml.claude.iteration_feedback;

        let mut completed = false;
        let mut phase_aborted = false;
        // Accumulators for budget-exhaustion diagnostics
        let mut total_blockers_raised: usize = 0;
        let mut any_progress_signaled = false;
        let mut total_pivots: usize = 0;
        for iter in 1..=phase.budget {
            // === AUTONOMOUS MODE: Check progress before continuing ===
            if phase.permission_mode == PermissionMode::Autonomous && iter > 1 {
                if let Some(ref mut auto_strategy) = autonomous_strategy {
                    let pivot_was_issued = auto_strategy.stale_handler.pivot_issued;
                    match auto_strategy.check_stale_progress(&phase, &mut progress_tracker) {
                        IterationDecision::StopPhase => {
                            println!("  Phase stopped: no progress after pivot");
                            break;
                        }
                        IterationDecision::Continue
                            if !pivot_was_issued && auto_strategy.stale_handler.pivot_issued =>
                        {
                            // Pivot was just issued — inject prompt
                            previous_feedback = Some(auto_strategy.pivot_prompt().to_string());
                        }
                        _ => {}
                    }
                } else if !gate.check_autonomous_progress(&progress_tracker) {
                    // Interactive fallback
                    match gate.prompt_no_progress()? {
                        IterationDecision::Continue => {
                            progress_tracker.stale_iterations = 0;
                        }
                        IterationDecision::StopPhase => {
                            println!("  Phase stopped due to no progress");
                            break;
                        }
                        IterationDecision::Abort => {
                            println!("  Orchestrator aborted by user");
                            phase_aborted = true;
                            break;
                        }
                        IterationDecision::Skip => {
                            continue;
                        }
                    }
                }
            }

            // Run PreIteration hooks
            let pre_iter_result = hook_manager.run_pre_iteration(&phase, iter).await?;

            match pre_iter_result.action {
                HookAction::Block => {
                    if let Some(msg) = &pre_iter_result.message {
                        println!("  PreIteration hook blocked: {}", msg);
                    }
                    break;
                }
                HookAction::Skip => {
                    if let Some(msg) = &pre_iter_result.message {
                        println!("  PreIteration hook skipped iteration: {}", msg);
                    }
                    continue;
                }
                _ => {}
            }

            ui.start_iteration(iter, phase.budget);

            // Check if compaction is needed before this iteration
            if let Some(summary_text) = compaction_manager.compact_if_needed() {
                if cli.verbose {
                    println!("  Context compacted: {}", compaction_manager.status());
                }
                // Record compaction in audit
                if let Some(compaction) = compaction_manager.last_compaction() {
                    phase_audit.add_compaction_event(
                        compaction.iterations_summarized,
                        compaction.original_chars,
                        compaction.summary_chars,
                    );
                }
                current_prompt_context = Some(PromptContext::with_compaction(summary_text));
                // Reset session on compaction — the compacted context replaces history
                active_session_id = None;
                previous_feedback = None;
            }

            // Run iteration with optional compaction context, session resumption, and feedback
            let result = runner
                .run_iteration_with_context(
                    &phase,
                    iter,
                    Some(ui.clone()),
                    current_prompt_context.as_ref(),
                    if session_continuity_enabled {
                        active_session_id.as_deref()
                    } else {
                        None
                    },
                    if iteration_feedback_enabled {
                        previous_feedback.as_deref()
                    } else {
                        None
                    },
                )
                .await?;

            // Compute changes
            let changes = tracker.compute_changes(&snapshot_sha)?;
            ui.update_files(&changes);

            // === READONLY MODE: Validate no modifications ===
            if phase.permission_mode == PermissionMode::Readonly
                && let Err(e) = gate.validate_readonly_changes(&phase, &changes)
            {
                println!("  {} {}", console::style("Error:").red().bold(), e);
                ui.phase_failed(&phase.number, "readonly mode violation");
                phase_audit.finish(
                    PhaseOutcome::Error {
                        message: e.to_string(),
                    },
                    changes.clone(),
                );
                break;
            }

            // Show individual file changes
            for path in &changes.files_added {
                ui.show_file_change(path, forge::audit::ChangeType::Added);
            }
            for path in &changes.files_modified {
                ui.show_file_change(path, forge::audit::ChangeType::Modified);
            }

            // Accumulate cross-iteration signal diagnostics for budget-exhaustion reporting
            total_blockers_raised += result.signals.blockers.len();
            if result.signals.latest_progress().is_some() {
                any_progress_signaled = true;
            }
            total_pivots += result.signals.pivots.len();

            // Update progress tracker for autonomous mode
            let progress_pct = result.signals.latest_progress();
            progress_tracker.update(&changes, progress_pct);

            // Capture session ID for --resume in next iteration
            if let Some(ref sid) = result.session.session_id {
                active_session_id = Some(sid.clone());
            }

            // Build iteration feedback for next iteration
            previous_feedback = IterationFeedback::new()
                .with_iteration_status(iter, phase.budget, result.promise_found)
                .with_git_changes(&changes)
                .with_signals(&result.signals)
                .build();

            // Record iteration in compaction manager
            let output_summary = extract_output_summary(&result.output, 100);
            compaction_manager.record_iteration(
                iter,
                result.session.prompt_chars,
                result.session.output_chars,
                &changes,
                &result.signals,
                &output_summary,
            );

            // Show context status in verbose mode
            if cli.verbose && iter > 1 {
                println!("  {}", compaction_manager.status());
            }

            // Run PostIteration hooks with signals
            let post_iter_result = hook_manager
                .run_post_iteration_with_signals(
                    &phase,
                    iter,
                    &changes,
                    result.promise_found,
                    Some(&result.output),
                    &result.signals,
                )
                .await?;

            // Handle blockers - pause and prompt user if there are unacknowledged blockers
            if result.signals.has_unacknowledged_blockers() {
                let blockers = result.signals.unacknowledged_blockers();
                for blocker in &blockers {
                    ui.show_blocker(&blocker.description);
                }

                // Auto-continue if --yes flag is set
                let continue_anyway = if cli.yes {
                    println!(
                        "  {} {} blocker(s) detected, auto-continuing (--yes flag)",
                        console::style("⚠").yellow(),
                        blockers.len()
                    );
                    true
                } else {
                    // Prompt user about blockers
                    use dialoguer::Confirm;
                    match Confirm::new()
                        .with_prompt(format!(
                            "{} blocker(s) detected. Continue anyway?",
                            blockers.len()
                        ))
                        .default(false)
                        .interact()
                    {
                        Ok(answer) => answer,
                        Err(e) => {
                            eprintln!(
                                "Warning: Could not display blocker confirmation dialog: {}. \
                                 Stopping. Re-run with --yes to auto-continue past blockers.",
                                e
                            );
                            false
                        }
                    }
                };

                if !continue_anyway {
                    ui.phase_failed(&phase.number, "User stopped due to blockers");
                    phase_audit.finish(PhaseOutcome::UserAborted, changes.clone());
                    break;
                }
            }

            // PostIteration hook can override promise detection
            let should_complete = match post_iter_result.action {
                HookAction::Block => {
                    if let Some(msg) = &post_iter_result.message {
                        println!("  PostIteration hook blocked: {}", msg);
                    }
                    false
                }
                _ => result.promise_found,
            };

            if should_complete {
                ui.iteration_success(iter);
                phase_audit.finish(PhaseOutcome::Completed { iteration: iter }, changes.clone());
                state.save(&phase.number, iter, "completed")?;
                previous_changes = Some(changes);
                completed = true;
                break;
            } else {
                // Show progress if available
                if let Some(pct) = result.signals.latest_progress() {
                    ui.iteration_bar_message(iter, phase.budget, &format!("{}% done", pct));
                }
                ui.iteration_continue(iter);
            }

            tokio::time::sleep(tokio::time::Duration::from_secs(2)).await;
        }

        // Handle phase abort (exit orchestrator entirely)
        if phase_aborted {
            audit.finish_run()?;
            return Ok(());
        }

        if !completed {
            let changes = tracker.compute_changes(&snapshot_sha)?;

            // Run OnFailure hooks
            let failure_result = hook_manager
                .run_on_failure(&phase, phase.budget, &changes)
                .await?;

            if let Some(msg) = &failure_result.message {
                println!("  OnFailure hook: {}", msg);
            }

            phase_audit.finish(PhaseOutcome::MaxIterationsReached, changes);
            state.save(&phase.number, phase.budget, "max_iterations")?;
            ui.phase_failed(&phase.number, "max iterations reached");

            // Actionable budget-exhaustion summary
            println!();
            println!(
                "  {} Phase '{}' exhausted its budget of {} iteration(s) without emitting the promise tag '{}'.",
                console::style("Budget exhausted:").red().bold(),
                phase.name,
                phase.budget,
                phase.promise,
            );
            // Summarize what signals were observed across the whole phase
            let progress_note = if any_progress_signaled {
                "progress was signaled at least once".to_string()
            } else {
                "no <progress> signals were ever emitted".to_string()
            };
            let blockers_note = blocker_note(total_blockers_raised);
            let pivots_note = pivot_note(total_pivots);
            println!("  Summary: {progress_note}; {blockers_note}; {pivots_note}.");
            println!(
                "  Tip: Verify the promise tag in your phases config matches exactly \
                (case-sensitive). Run 'forge audit --last' to inspect Claude's raw output."
            );
            println!(
                "  Tip: Use <progress>N%</progress> and <blocker>reason</blocker> tags \
                in your phase prompt to help diagnose stuck phases."
            );
        } else {
            // Run PostPhase hooks
            let post_phase_result = hook_manager
                .run_post_phase(
                    &phase,
                    phase.budget,
                    previous_changes
                        .as_ref()
                        .unwrap_or(&FileChangeSummary::default()),
                    true,
                )
                .await?;

            if let Some(msg) = &post_phase_result.message
                && cli.verbose
            {
                println!("  PostPhase hook: {}", msg);
            }

            ui.phase_complete(&phase.number);
        }

        audit.add_phase(phase_audit)?;

        tokio::time::sleep(tokio::time::Duration::from_secs(5)).await;
    }

    let run_file = audit.finish_run()?;
    println!("Audit log saved to: {}", run_file.display());

    Ok(())
}

/// Build a human-readable note for the number of blockers raised during a phase.
///
/// Returns a string like "3 blockers raised" or "no blockers raised".
/// This is pure logic that can be unit-tested without external processes.
pub fn blocker_note(total_blockers_raised: usize) -> String {
    if total_blockers_raised > 0 {
        format!(
            "{} blocker{} raised",
            total_blockers_raised,
            if total_blockers_raised == 1 { "" } else { "s" }
        )
    } else {
        "no blockers raised".to_string()
    }
}

/// Build a human-readable note for the number of pivots signaled during a phase.
///
/// Returns a string like "2 pivots signaled" or "no pivots signaled".
/// This is pure logic that can be unit-tested without external processes.
pub fn pivot_note(total_pivots: usize) -> String {
    if total_pivots > 0 {
        format!(
            "{} pivot{} signaled",
            total_pivots,
            if total_pivots == 1 { "" } else { "s" }
        )
    } else {
        "no pivots signaled".to_string()
    }
}

/// Resolve the phase start string from an optional user-supplied value and
/// last-completed state.
///
/// - If `start_phase` is `Some(s)`, that string is returned directly.
/// - Otherwise the next phase after `last_completed` is returned (zero-padded
///   to two digits), falling back to `"01"` when nothing has been completed.
///
/// This is pure logic that can be unit-tested without external processes.
pub fn resolve_start_phase(start_phase: Option<&str>, last_completed: Option<&str>) -> String {
    start_phase.map(|s| s.to_string()).unwrap_or_else(|| {
        last_completed
            .map(|p| format!("{:02}", p.parse::<u32>().unwrap_or(0) + 1))
            .unwrap_or_else(|| "01".to_string())
    })
}

pub async fn run_single_phase(cli: &Cli, project_dir: PathBuf, phase_num: &str) -> Result<()> {
    use forge::init::get_forge_dir;
    use forge::phase::PhasesFile;

    check_run_prerequisites(&project_dir)?;

    // Load phases from phases.json
    let forge_dir = get_forge_dir(&project_dir);
    let phases_file = forge_dir.join("phases.json");
    let pf = PhasesFile::load(&phases_file)?;

    let phase = pf
        .phases
        .into_iter()
        .find(|p| p.number == phase_num)
        .ok_or_else(|| anyhow::anyhow!("Unknown phase: {}", phase_num))?;

    run_orchestrator(cli, project_dir, Some(phase.number)).await
}

#[cfg(test)]
mod tests {
    use super::*;

    // ── blocker_note ──────────────────────────────────────────────────────────

    #[test]
    fn blocker_note_zero_returns_no_blockers() {
        assert_eq!(blocker_note(0), "no blockers raised");
    }

    #[test]
    fn blocker_note_one_is_singular() {
        let note = blocker_note(1);
        assert_eq!(note, "1 blocker raised");
        assert!(note.contains('1'), "expected count in note: {note}");
        assert!(
            note.contains("blocker"),
            "expected 'blocker' in note: {note}"
        );
        // Must NOT contain the plural suffix "s" (right after "blocker")
        assert!(
            !note.contains("blockers"),
            "note should be singular: {note}"
        );
    }

    #[test]
    fn blocker_note_many_is_plural() {
        let note = blocker_note(3);
        assert_eq!(note, "3 blockers raised");
        assert!(note.contains('3'), "expected count in note: {note}");
        assert!(note.contains("blockers"), "expected plural in note: {note}");
    }

    // ── pivot_note ────────────────────────────────────────────────────────────

    #[test]
    fn pivot_note_zero_returns_no_pivots() {
        assert_eq!(pivot_note(0), "no pivots signaled");
    }

    #[test]
    fn pivot_note_one_is_singular() {
        let note = pivot_note(1);
        assert_eq!(note, "1 pivot signaled");
        assert!(note.contains('1'), "expected count in note: {note}");
        assert!(note.contains("pivot"), "expected 'pivot' in note: {note}");
        assert!(!note.contains("pivots"), "note should be singular: {note}");
    }

    #[test]
    fn pivot_note_many_is_plural() {
        let note = pivot_note(5);
        assert_eq!(note, "5 pivots signaled");
        assert!(note.contains('5'), "expected count in note: {note}");
        assert!(note.contains("pivots"), "expected plural in note: {note}");
    }

    // ── resolve_start_phase ───────────────────────────────────────────────────

    #[test]
    fn resolve_start_phase_explicit_overrides_state() {
        // User explicitly requested phase "03"; last completed was "02"
        let result = resolve_start_phase(Some("03"), Some("02"));
        assert_eq!(result, "03");
    }

    #[test]
    fn resolve_start_phase_derives_next_from_last_completed() {
        // No explicit start; last completed is "04" → next is "05"
        let result = resolve_start_phase(None, Some("04"));
        assert_eq!(result, "05");
    }

    #[test]
    fn resolve_start_phase_zero_pads_single_digit() {
        // Last completed "1" → next is "02"
        let result = resolve_start_phase(None, Some("1"));
        assert_eq!(result, "02");
    }

    #[test]
    fn resolve_start_phase_falls_back_to_01_when_nothing_completed() {
        let result = resolve_start_phase(None, None);
        assert_eq!(result, "01");
    }

    #[test]
    fn resolve_start_phase_handles_non_numeric_last_completed_gracefully() {
        // parse::<u32>() fails → treated as 0 → next is "01"
        let result = resolve_start_phase(None, Some("abc"));
        assert_eq!(result, "01");
    }

    // ── check_run_prerequisites ───────────────────────────────────────────────

    #[test]
    fn check_run_prerequisites_fails_on_uninitialized_directory() {
        let tmp = tempfile::tempdir().expect("tempdir");
        let err = check_run_prerequisites(tmp.path()).unwrap_err();
        let msg = err.to_string();
        assert!(
            msg.contains("forge init"),
            "expected 'forge init' hint in error: {msg}"
        );
    }
}

//! DAG scheduler for computing execution order and managing phase states.
//!
//! The scheduler computes execution waves - groups of phases that can run in parallel
//! because their dependencies are satisfied.

use crate::dag::builder::{DagBuilder, PhaseGraph, PhaseIndex};
use crate::phase::Phase;
use anyhow::Result;
use serde::{Deserialize, Serialize};
use std::collections::HashSet;

/// Configuration for the DAG scheduler.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct DagConfig {
    /// Maximum phases to run in parallel
    pub max_parallel: usize,
    /// Stop all phases on first failure
    pub fail_fast: bool,
    /// Enable swarm hooks for marked phases
    pub swarm_enabled: bool,
    /// Backend for swarm execution
    pub swarm_backend: SwarmBackend,
    /// Review configuration
    pub review: ReviewConfig,
    /// Enable dynamic decomposition
    pub decomposition_enabled: bool,
    /// Budget percentage threshold for decomposition
    pub decomposition_threshold: u32,
    /// Finding types to always escalate
    pub escalation_types: Vec<String>,
}

impl Default for DagConfig {
    fn default() -> Self {
        Self {
            max_parallel: 4,
            fail_fast: false,
            swarm_enabled: true,
            swarm_backend: SwarmBackend::Auto,
            review: ReviewConfig::default(),
            decomposition_enabled: true,
            decomposition_threshold: 50,
            escalation_types: Vec::new(),
        }
    }
}

impl DagConfig {
    /// Create a config with specific max parallelism.
    pub fn with_max_parallel(mut self, max: usize) -> Self {
        self.max_parallel = max;
        self
    }

    /// Enable or disable fail-fast mode.
    pub fn with_fail_fast(mut self, fail_fast: bool) -> Self {
        self.fail_fast = fail_fast;
        self
    }

    /// Enable or disable swarm execution.
    pub fn with_swarm_enabled(mut self, enabled: bool) -> Self {
        self.swarm_enabled = enabled;
        self
    }

    /// Set the swarm backend.
    pub fn with_swarm_backend(mut self, backend: SwarmBackend) -> Self {
        self.swarm_backend = backend;
        self
    }

    /// Set the review configuration.
    pub fn with_review(mut self, review: ReviewConfig) -> Self {
        self.review = review;
        self
    }

    /// Enable or disable dynamic decomposition.
    pub fn with_decomposition(mut self, enabled: bool) -> Self {
        self.decomposition_enabled = enabled;
        self
    }

    /// Set the decomposition budget threshold.
    pub fn with_decomposition_threshold(mut self, threshold: u32) -> Self {
        self.decomposition_threshold = threshold;
        self
    }

    /// Set the escalation types.
    pub fn with_escalation_types(mut self, types: Vec<String>) -> Self {
        self.escalation_types = types;
        self
    }
}

/// Backend for swarm execution.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, Default)]
#[serde(rename_all = "snake_case")]
pub enum SwarmBackend {
    /// Auto-detect the best backend
    #[default]
    Auto,
    /// Run in the same process
    InProcess,
    /// Use tmux for parallel terminals
    Tmux,
    /// Use iTerm2 for parallel terminals (macOS)
    Iterm2,
}

/// Review configuration for the DAG scheduler.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ReviewConfig {
    /// Whether reviews are enabled
    pub enabled: bool,
    /// Default specialists to use if phase has none
    pub default_specialists: Vec<String>,
    /// Review mode
    pub mode: ReviewMode,
    /// Max fix attempts for auto mode
    pub max_fix_attempts: u32,
    /// Arbiter confidence threshold
    pub arbiter_confidence: f64,
}

impl Default for ReviewConfig {
    fn default() -> Self {
        Self {
            enabled: false,
            default_specialists: Vec::new(),
            mode: ReviewMode::Manual,
            max_fix_attempts: 2,
            arbiter_confidence: 0.7,
        }
    }
}

impl ReviewConfig {
    /// Create a config with reviews enabled.
    pub fn enabled(specialists: Vec<String>) -> Self {
        Self {
            enabled: true,
            default_specialists: specialists,
            ..Default::default()
        }
    }

    /// Set the review mode.
    pub fn with_mode(mut self, mode: ReviewMode) -> Self {
        self.mode = mode;
        self
    }
}

/// Review resolution mode.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, Default)]
#[serde(rename_all = "snake_case")]
pub enum ReviewMode {
    /// Always pause for human input on failures
    #[default]
    Manual,
    /// Attempt auto-fix, retry up to max_fix_attempts
    Auto,
    /// LLM arbiter decides based on severity and context
    Arbiter,
}

/// Status of a phase in the DAG.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize, Default)]
#[serde(rename_all = "snake_case")]
pub enum PhaseStatus {
    /// Phase is waiting to run
    #[default]
    Pending,
    /// Phase is waiting for dependencies
    Blocked { waiting_on: Vec<String> },
    /// Phase is ready to run (dependencies satisfied)
    Ready,
    /// Phase is currently running
    Running { started_at_ms: u64 },
    /// Phase completed successfully
    Completed { iterations: u32 },
    /// Phase failed
    Failed { error: String },
    /// Phase was skipped (due to dependency failure)
    Skipped,
}

impl PhaseStatus {
    /// Check if the phase is in a terminal state.
    pub fn is_terminal(&self) -> bool {
        matches!(
            self,
            Self::Completed { .. } | Self::Failed { .. } | Self::Skipped
        )
    }

    /// Check if the phase completed successfully.
    pub fn is_success(&self) -> bool {
        matches!(self, Self::Completed { .. })
    }

    /// Check if the phase is ready to run.
    pub fn is_ready(&self) -> bool {
        matches!(self, Self::Ready)
    }

    /// Check if the phase is running.
    pub fn is_running(&self) -> bool {
        matches!(self, Self::Running { .. })
    }
}

/// A node in the DAG representing a phase with its current status.
#[derive(Debug, Clone)]
pub struct PhaseNode {
    /// The phase definition
    pub phase: Phase,
    /// Current status
    pub status: PhaseStatus,
    /// Index in the graph
    pub index: PhaseIndex,
}

impl PhaseNode {
    /// Create a new phase node.
    pub fn new(phase: Phase, index: PhaseIndex) -> Self {
        Self {
            phase,
            status: PhaseStatus::Pending,
            index,
        }
    }

    /// Check if this phase should use swarm execution.
    pub fn is_swarm_enabled(&self) -> bool {
        // A phase is swarm-enabled if it has swarm configuration
        // For now, check if it has swarm strategy in config (would need phase extension)
        // or if it has multiple sub-tasks
        !self.phase.sub_phases.is_empty()
    }
}

/// The main DAG scheduler.
#[derive(Debug)]
pub struct DagScheduler {
    /// The underlying phase graph
    graph: PhaseGraph,
    /// Phase nodes with status
    nodes: Vec<PhaseNode>,
    /// Configuration
    config: DagConfig,
    /// Set of completed phase indices
    completed: HashSet<PhaseIndex>,
    /// Set of failed phase indices
    failed: HashSet<PhaseIndex>,
}

impl DagScheduler {
    /// Create a DAG scheduler from a list of phases.
    pub fn from_phases(phases: &[Phase], config: DagConfig) -> Result<Self> {
        let graph = DagBuilder::new(phases.to_vec()).build()?;

        let nodes: Vec<PhaseNode> = graph
            .phases()
            .iter()
            .enumerate()
            .map(|(i, p)| PhaseNode::new(p.clone(), i))
            .collect();

        Ok(Self {
            graph,
            nodes,
            config,
            completed: HashSet::new(),
            failed: HashSet::new(),
        })
    }

    /// Get the number of phases in the DAG.
    pub fn phase_count(&self) -> usize {
        self.graph.len()
    }

    /// Get a phase node by its number.
    pub fn get_node(&self, number: &str) -> Option<&PhaseNode> {
        self.graph.get_index(number).and_then(|i| self.nodes.get(i))
    }

    /// Get a mutable reference to a phase node.
    pub fn get_node_mut(&mut self, number: &str) -> Option<&mut PhaseNode> {
        let index = self.graph.get_index(number)?;
        self.nodes.get_mut(index)
    }

    /// Get all phase nodes.
    pub fn nodes(&self) -> &[PhaseNode] {
        &self.nodes
    }

    /// Get the configuration.
    pub fn config(&self) -> &DagConfig {
        &self.config
    }

    /// Compute execution waves - groups of phases that can run in parallel.
    ///
    /// Returns a list of waves, where each wave is a list of phase numbers
    /// that can be executed in parallel once all previous waves complete.
    pub fn compute_waves(&self) -> Vec<Vec<String>> {
        let mut waves = Vec::new();
        let mut completed: HashSet<PhaseIndex> = HashSet::new();

        loop {
            // Find all phases whose dependencies are satisfied and not yet completed
            let ready: Vec<String> = self
                .graph
                .phases()
                .iter()
                .enumerate()
                .filter_map(|(i, phase)| {
                    if completed.contains(&i) {
                        return None;
                    }
                    if self.graph.dependencies_satisfied(i, &completed) {
                        Some(phase.number.clone())
                    } else {
                        None
                    }
                })
                .collect();

            if ready.is_empty() {
                break;
            }

            // Mark these phases as "completed" for the next iteration
            for number in &ready {
                if let Some(idx) = self.graph.get_index(number) {
                    completed.insert(idx);
                }
            }

            waves.push(ready);
        }

        waves
    }

    /// Get phases that are ready to run (dependencies satisfied, not started).
    pub fn get_ready_phases(&self) -> Vec<&PhaseNode> {
        self.nodes
            .iter()
            .filter(|node| {
                if !matches!(node.status, PhaseStatus::Pending) {
                    return false;
                }
                self.graph
                    .dependencies_satisfied(node.index, &self.completed)
            })
            .collect()
    }

    /// Mark a phase as running.
    pub fn mark_running(&mut self, number: &str) {
        if let Some(node) = self.get_node_mut(number) {
            node.status = PhaseStatus::Running {
                started_at_ms: std::time::SystemTime::now()
                    .duration_since(std::time::UNIX_EPOCH)
                    .unwrap_or_default()
                    .as_millis() as u64,
            };
        }
    }

    /// Mark a phase as completed.
    pub fn mark_completed(&mut self, number: &str, iterations: u32) {
        if let Some(idx) = self.graph.get_index(number) {
            if let Some(node) = self.nodes.get_mut(idx) {
                node.status = PhaseStatus::Completed { iterations };
            }
            self.completed.insert(idx);
        }
    }

    /// Mark a phase as failed.
    pub fn mark_failed(&mut self, number: &str, error: &str) {
        if let Some(idx) = self.graph.get_index(number) {
            if let Some(node) = self.nodes.get_mut(idx) {
                node.status = PhaseStatus::Failed {
                    error: error.to_string(),
                };
            }
            self.failed.insert(idx);

            // If fail_fast, skip all dependent phases
            if self.config.fail_fast {
                self.skip_dependents(idx);
            }
        }
    }

    /// Mark a phase as skipped.
    pub fn mark_skipped(&mut self, number: &str) {
        if let Some(idx) = self.graph.get_index(number) {
            if let Some(node) = self.nodes.get_mut(idx) {
                node.status = PhaseStatus::Skipped;
            }
            self.failed.insert(idx); // Treat skipped as failed for dependency purposes
        }
    }

    /// Skip all phases that depend on a failed phase.
    fn skip_dependents(&mut self, failed_idx: PhaseIndex) {
        let dependents: Vec<PhaseIndex> = self.graph.dependents(failed_idx).to_vec();
        for dep_idx in dependents {
            if let Some(node) = self.nodes.get_mut(dep_idx)
                && !node.status.is_terminal()
            {
                node.status = PhaseStatus::Skipped;
                self.failed.insert(dep_idx);
                // Recursively skip dependents
                self.skip_dependents(dep_idx);
            }
        }
    }

    /// Check if all phases are complete (success or failure).
    pub fn all_complete(&self) -> bool {
        self.nodes.iter().all(|n| n.status.is_terminal())
    }

    /// Check if all phases completed successfully.
    pub fn all_success(&self) -> bool {
        self.nodes.iter().all(|n| n.status.is_success())
    }

    /// Get the number of completed phases.
    pub fn completed_count(&self) -> usize {
        self.completed.len()
    }

    /// Get the number of failed phases.
    pub fn failed_count(&self) -> usize {
        self.failed.len()
    }

    /// Get completion percentage.
    pub fn completion_percentage(&self) -> f64 {
        if self.nodes.is_empty() {
            return 100.0;
        }
        let terminal = self.nodes.iter().filter(|n| n.status.is_terminal()).count();
        (terminal as f64 / self.nodes.len() as f64) * 100.0
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn phase(number: &str, deps: Vec<&str>) -> Phase {
        Phase::new(
            number,
            &format!("Phase {}", number),
            &format!("{} DONE", number),
            5,
            "test",
            deps.into_iter().map(String::from).collect(),
        )
    }

    #[test]
    fn test_wave_computation_linear() {
        // Linear: 01 -> 02 -> 03
        let phases = vec![
            phase("01", vec![]),
            phase("02", vec!["01"]),
            phase("03", vec!["02"]),
        ];

        let scheduler = DagScheduler::from_phases(&phases, DagConfig::default()).unwrap();
        let waves = scheduler.compute_waves();

        assert_eq!(waves.len(), 3);
        assert_eq!(waves[0], vec!["01"]);
        assert_eq!(waves[1], vec!["02"]);
        assert_eq!(waves[2], vec!["03"]);
    }

    #[test]
    fn test_wave_computation_diamond() {
        // Diamond: 01 -> (02, 03) -> 04
        let phases = vec![
            phase("01", vec![]),
            phase("02", vec!["01"]),
            phase("03", vec!["01"]),
            phase("04", vec!["02", "03"]),
        ];

        let scheduler = DagScheduler::from_phases(&phases, DagConfig::default()).unwrap();
        let waves = scheduler.compute_waves();

        assert_eq!(waves.len(), 3);
        assert_eq!(waves[0], vec!["01"]);
        assert!(waves[1].contains(&"02".to_string()));
        assert!(waves[1].contains(&"03".to_string()));
        assert_eq!(waves[2], vec!["04"]);
    }

    #[test]
    fn test_wave_computation_multiple_roots() {
        // Multiple roots: (01, 02) -> 03
        let phases = vec![
            phase("01", vec![]),
            phase("02", vec![]),
            phase("03", vec!["01", "02"]),
        ];

        let scheduler = DagScheduler::from_phases(&phases, DagConfig::default()).unwrap();
        let waves = scheduler.compute_waves();

        assert_eq!(waves.len(), 2);
        assert!(waves[0].contains(&"01".to_string()));
        assert!(waves[0].contains(&"02".to_string()));
        assert_eq!(waves[1], vec!["03"]);
    }

    #[test]
    fn test_ready_phases() {
        let phases = vec![
            phase("01", vec![]),
            phase("02", vec!["01"]),
            phase("03", vec!["01"]),
        ];

        let mut scheduler = DagScheduler::from_phases(&phases, DagConfig::default()).unwrap();

        // Initially only phase 01 is ready
        let ready = scheduler.get_ready_phases();
        assert_eq!(ready.len(), 1);
        assert_eq!(ready[0].phase.number, "01");

        // Mark 01 as completed
        scheduler.mark_completed("01", 3);

        // Now 02 and 03 should be ready
        let ready = scheduler.get_ready_phases();
        assert_eq!(ready.len(), 2);
    }

    #[test]
    fn test_fail_fast() {
        let phases = vec![
            phase("01", vec![]),
            phase("02", vec!["01"]),
            phase("03", vec!["02"]),
        ];

        let mut scheduler =
            DagScheduler::from_phases(&phases, DagConfig::default().with_fail_fast(true)).unwrap();

        // Mark 01 as failed
        scheduler.mark_failed("01", "test error");

        // Both 02 and 03 should be skipped
        assert!(matches!(scheduler.nodes[1].status, PhaseStatus::Skipped));
        assert!(matches!(scheduler.nodes[2].status, PhaseStatus::Skipped));
    }

    #[test]
    fn test_completion_tracking() {
        let phases = vec![phase("01", vec![]), phase("02", vec!["01"])];

        let mut scheduler = DagScheduler::from_phases(&phases, DagConfig::default()).unwrap();

        assert_eq!(scheduler.completion_percentage(), 0.0);
        assert!(!scheduler.all_complete());

        scheduler.mark_completed("01", 3);
        assert_eq!(scheduler.completion_percentage(), 50.0);

        scheduler.mark_completed("02", 5);
        assert_eq!(scheduler.completion_percentage(), 100.0);
        assert!(scheduler.all_complete());
        assert!(scheduler.all_success());
    }
}

