  1→use crate::audit::{ChangeType, FileChangeSummary};
  2→use crate::signals::IterationSignals;
  3→use crate::ui::icons::{
  4→    BLOCKER, CHECK, CROSS, FILE_DEL, FILE_MOD, FILE_NEW, FOLDER, PIVOT, PROGRESS, SPARKLE,
  5→};
  6→use console::style;
  7→use indicatif::{MultiProgress, ProgressBar, ProgressStyle};
  8→use std::path::Path;
  9→use std::sync::atomic::{AtomicU32, Ordering};
 10→use std::time::Duration;
 11→
 12→/// Terminal UI for the Forge orchestrator, rendered via `indicatif` progress bars.
 13→///
 14→/// Three bars are stacked vertically:
 15→/// - Phase bar — tracks how many phases have completed
 16→/// - Iteration bar — spinner with the current iteration number and live status
 17→/// - File bar — running tally of added/modified/deleted files since the run began
 18→///
 19→/// All methods coordinate output via `indicatif`'s `MultiProgress` internally.
 20→pub struct OrchestratorUI {
 21→    multi: MultiProgress,
 22→    phase_bar: ProgressBar,
 23→    iteration_bar: ProgressBar,
 24→    file_bar: ProgressBar,
 25→    verbose: bool,
 26→    current_iter: AtomicU32,
 27→    max_iter: AtomicU32,
 28→}
 29→
 30→impl OrchestratorUI {
 31→    /// Create the UI and add all three progress bars to the multiplex renderer.
 32→    ///
 33→    /// # Arguments
 34→    /// * `total_phases` — total number of phases in the run, sizes the phase bar
 35→    /// * `verbose` — when `true`, per-step and thinking output is printed;
 36→    ///   when `false` only tool-use lines are shown
 37→    ///
 38→    /// Call this once at orchestrator startup, before `start_phase`.
 39→    pub fn new(total_phases: u64, verbose: bool) -> Self {
 40→        let multi = MultiProgress::new();
 41→
 42→        let phase_style = ProgressStyle::default_bar()
 43→            .template("{prefix:.bold.dim} [{bar:40.cyan/blue}] {pos}/{len} {msg}")
 44→            .expect("progress bar template is a valid static string")
 45→            .progress_chars("█▓▒░");
 46→
 47→        let phase_bar = multi.add(ProgressBar::new(total_phases));
 48→        phase_bar.set_style(phase_style);
 49→        phase_bar.set_prefix("Phases");
 50→
 51→        let iteration_style = ProgressStyle::default_spinner()
 52→            .template("{prefix:.bold.dim} {spinner} {msg}")
 53→            .expect("progress bar template is a valid static string");
 54→
 55→        let iteration_bar = multi.add(ProgressBar::new_spinner());
 56→        iteration_bar.set_style(iteration_style);
 57→        iteration_bar.set_prefix("  Iter");
 58→
 59→        let file_style = ProgressStyle::default_bar()
 60→            .template("{prefix:.bold.dim} {msg}")
 61→            .expect("progress bar template is a valid static string");
 62→
 63→        let file_bar = multi.add(ProgressBar::new(0));
 64→        file_bar.set_style(file_style);
 65→        file_bar.set_prefix(" Files");
 66→
 67→        Self {
 68→            multi,
 69→            phase_bar,
 70→            iteration_bar,
 71→            file_bar,
 72→            verbose,
 73→            current_iter: AtomicU32::new(0),
 74→            max_iter: AtomicU32::new(0),
 75→        }
 76→    }
 77→
 78→    /// Print a line via `MultiProgress`, falling back to `eprintln!` if the rich UI fails.
 79→    ///
 80→    /// This prevents silent loss of critical user-facing messages (blockers, progress,
 81→    /// pivots) when the terminal or stdout is unavailable.
 82→    fn print_line(&self, msg: impl AsRef<str>) {
 83→        if self.multi.println(msg.as_ref()).is_err() {
 84→            eprintln!("{}", msg.as_ref());
 85→        }
 86→    }
 87→
 88→    /// Update the phase bar message to reflect the phase about to execute.
 89→    ///
 90→    /// Does **not** increment the phase counter — call [`Self::phase_complete`] to advance it.
 91→    ///
 92→    /// # Arguments
 93→    /// * `phase` — phase identifier (e.g. `"01"`)
 94→    /// * `description` — human-readable phase name shown in the status line
 95→    pub fn start_phase(&self, phase: &str, description: &str) {
 96→        self.phase_bar
 97→            .set_message(format!("{}: {}", style(phase).yellow(), description));
 98→    }
 99→
100→    /// Record iteration counters and start the spinner animation.
101→    ///
102→    /// Enables a 100 ms tick on the iteration spinner. Call [`Self::iteration_success`],
103→    /// [`Self::iteration_continue`], or [`Self::iteration_error`] to stop the spinner.
104→    ///
105→    /// # Arguments
106→    /// * `iter` — 1-based current iteration number
107→    /// * `max` — total iteration budget for this phase
108→    pub fn start_iteration(&self, iter: u32, max: u32) {
109→        self.current_iter.store(iter, Ordering::SeqCst);
110→        self.max_iter.store(max, Ordering::SeqCst);
111→        self.iteration_bar.set_message(format!(
112→            "Running iteration {}/{} {}",
113→            style(iter).cyan(),
114→            max,
115→            style("(starting...)").dim()
116→        ));
117→        self.iteration_bar
118→            .enable_steady_tick(Duration::from_millis(100));
119→    }
120→
121→    /// Update the iteration spinner message with a short status string.
122→    ///
123→    /// In verbose mode the message is also printed as a dim indented line.
124→    ///
125→    /// # Arguments
126→    /// * `msg` — short lowercase status string, e.g. `"running claude"`
127→    pub fn log_step(&self, msg: &str) {
128→        let iter = self.current_iter.load(Ordering::SeqCst);
129→        let max = self.max_iter.load(Ordering::SeqCst);
130→        self.iteration_bar.set_message(format!(
131→            "Running iteration {}/{} {}",
132→            style(iter).cyan(),
133→            max,
134→            style(format!("({})", msg)).dim()
135→        ));
136→        if self.verbose {
137→            self.print_line(format!("    {} {}", style("→").dim(), style(msg).dim()));
138→        }
139→    }
140→
141→    /// Refresh the iteration spinner message with wall-clock elapsed time.
142→    ///
143→    /// Intended to be called from a periodic timer task (e.g. every second).
144→    /// Formats as `Xs` or `Xm Ys` when >= 60 seconds.
145→    ///
146→    /// # Arguments
147→    /// * `elapsed` — duration since the current iteration began
148→    pub fn update_elapsed(&self, elapsed: Duration) {
149→        let iter = self.current_iter.load(Ordering::SeqCst);
150→        let max = self.max_iter.load(Ordering::SeqCst);
151→        let secs = elapsed.as_secs();
152→        let time_str = if secs >= 60 {
153→            format!("{}m {}s", secs / 60, secs % 60)
154→        } else {
155→            format!("{}s", secs)
156→        };
157→        self.iteration_bar.set_message(format!(
158→            "Running iteration {}/{} {}",
159→            style(iter).cyan(),
160→            max,
161→            style(format!("({})", time_str)).dim()
162→        ));
163→    }
